async fn ensure_kokoro_onnx_downloaded(model_dir: &std::path::Path) {
    // Ensure model dir exists
    let _ = tokio::fs::create_dir_all(model_dir).await;
    let voices_dir = model_dir.join("voices");
    let _ = tokio::fs::create_dir_all(&voices_dir).await;

    // Download ONNX model files (skip any that already exist)
    for (filename, url) in ONNX_DOWNLOADS {
        let dest = model_dir.join(filename);
        if !dest.exists() {
            if let Err(e) = download_file(url, &dest).await {
                eprintln!("Warning: could not download {}: {}", filename, e);
            }
        }
    }

    // Download voice bin files (skip any that already exist)
    for (voice_id, url) in ONNX_VOICE_DOWNLOADS {
        let dest = voices_dir.join(format!("{}.bin", voice_id));
        if !dest.exists() {
            if let Err(e) = download_file(url, &dest).await {
                eprintln!("Warning: could not download voice {}: {}", voice_id, e);
            }
        }
    }
}

fn benchmark_tts_onnx_throughput(c: &mut Criterion) {
    use torch_inference::core::kokoro_onnx::KokoroOnnxEngine;
    use torch_inference::core::tts_engine::{TTSEngine, SynthesisParams};
    use criterion::Throughput;

    let rt = tokio::runtime::Runtime::new().unwrap();
    let model_dir = std::path::PathBuf::from("models/kokoro-82m");
    let label = "kokoro-onnx";

    // Ensure model files are present (downloads skipped if files already exist)
    rt.block_on(ensure_kokoro_onnx_downloaded(&model_dir));

    // Verify at least one ONNX model file is present before proceeding
    let has_onnx = ONNX_DOWNLOADS.iter()
        .any(|(filename, _)| model_dir.join(filename).exists());
    if !has_onnx {
        eprintln!("Skipping {} — no ONNX model file in {:?}", label, model_dir);
        return;
    }

    let config_json = serde_json::json!({
        "model_dir": model_dir.to_str().unwrap(),
        "sample_rate": 24000
    });

    // Helper: creates a fresh engine and runs a warmup iteration.
    // We create one engine per criterion group to prevent ORT/CoreML session state
    // from leaking across group boundaries (which caused a mutex crash in group.finish()).
    let make_engine = || -> Option<KokoroOnnxEngine> {
        match KokoroOnnxEngine::new(&config_json) {
            Ok(e) => {
                rt.block_on(async {
                    let warmup = SynthesisParams {
                        voice: Some("af_heart".to_string()),
                        speed: 1.0, pitch: 1.0, language: None,
                    };
                    let _ = e.synthesize("warmup", &warmup).await;
                });
                Some(e)
            }
            Err(e) => {
                eprintln!("Failed to init {}: {}", label, e);
                None
            }
        }
    };

    // --- Throughput by text length (chars/sec) ---
    if let Some(engine) = make_engine() {
        let mut group = c.benchmark_group(format!("tts_throughput/{}", label));
        group.sample_size(10);
        group.measurement_time(Duration::from_secs(120));

        for &(text_label, text) in TTS_TEXTS {
            group.throughput(Throughput::Bytes(text.len() as u64));
            group.bench_with_input(
                BenchmarkId::new("chars_per_sec", text_label),
                &(text_label, text),
                |b, &(_, txt)| {
                    let params = SynthesisParams {
                        voice: Some("af_heart".to_string()),
                        speed: 1.0, pitch: 1.0, language: None,
                    };
                    b.iter(|| rt.block_on(async {
                        black_box(engine.synthesize(txt, &params).await.ok())
                    }));
                },
            );
        }
        group.finish();
    }

    // --- Throughput by voice (fixed medium text) ---
    if let Some(engine) = make_engine() {
        let mut group = c.benchmark_group(format!("tts_throughput_by_voice/{}", label));
        group.sample_size(10);
        group.measurement_time(Duration::from_secs(60));

        let text = TTS_TEXTS[1].1; // medium length
        group.throughput(Throughput::Bytes(text.len() as u64));

        for &voice in TTS_VOICES_ONNX {
            group.bench_with_input(
                BenchmarkId::new("voice", voice),
                &voice,
                |b, &v| {
                    let params = SynthesisParams {
                        voice: Some(v.to_string()),
                        speed: 1.0, pitch: 1.0, language: None,
                    };
                    b.iter(|| rt.block_on(async {
                        black_box(engine.synthesize(text, &params).await.ok())
                    }));
                },
            );
        }
        group.finish();
    }

    // --- Words per second (RTF proxy) across text lengths ---
    if let Some(engine) = make_engine() {
        let mut group = c.benchmark_group(format!("tts_rtf/{}", label));
        group.sample_size(10);
        group.measurement_time(Duration::from_secs(120));

        for &(text_label, text) in TTS_TEXTS {
            let word_count = text.split_whitespace().count() as u64;
            group.throughput(Throughput::Elements(word_count));
            group.bench_with_input(
                BenchmarkId::new("words_per_sec", text_label),
                &(text_label, text),
                |b, &(_, txt)| {
                    let params = SynthesisParams {
                        voice: Some("af_heart".to_string()),
                        speed: 1.0, pitch: 1.0, language: None,
                    };
                    b.iter(|| rt.block_on(async {
                        black_box(engine.synthesize(txt, &params).await.ok())
                    }));
                },
            );
        }
        group.finish();
    }

    // --- INT8 vs Full ONNX comparison (only when both files are present) ---
    // Both files live in the same dir; the engine picks whichever it finds first.
    // We rename one aside temporarily so each variant gets an isolated session.
    let full_onnx = model_dir.join("kokoro-v1_0.onnx");
    let int8_onnx = model_dir.join("kokoro-v1.0.int8.onnx");
    let text_medium = TTS_TEXTS[1].1;

    if full_onnx.exists() && int8_onnx.exists() {
        // Full ONNX
        if let Some(engine_full) = make_engine() {
            // INT8 ONNX — temporarily hide the full model so ORT picks int8
            let full_tmp = model_dir.join("kokoro-v1_0.onnx.bak");
            let _ = fs::rename(&full_onnx, &full_tmp);
            let engine_int8 = make_engine();
            let _ = fs::rename(&full_tmp, &full_onnx); // restore

            if let Some(engine_int8) = engine_int8 {
                let mut group = c.benchmark_group(format!("tts_quantization/{}", label));
                group.sample_size(10);
                group.measurement_time(Duration::from_secs(60));
                group.throughput(Throughput::Bytes(text_medium.len() as u64));

                group.bench_with_input(
                    BenchmarkId::new("quantization", "full"),
                    &"full",
                    |b, _| {
                        let params = SynthesisParams {
                            voice: Some("af_heart".to_string()),
                            speed: 1.0, pitch: 1.0, language: None,
                        };
                        b.iter(|| rt.block_on(async {
                            black_box(engine_full.synthesize(text_medium, &params).await.ok())
                        }));
                    },
                );

                group.bench_with_input(
                    BenchmarkId::new("quantization", "int8"),
                    &"int8",
                    |b, _| {
                        let params = SynthesisParams {
                            voice: Some("af_heart".to_string()),
                            speed: 1.0, pitch: 1.0, language: None,
                        };
                        b.iter(|| rt.block_on(async {
                            black_box(engine_int8.synthesize(text_medium, &params).await.ok())
                        }));
                    },
                );

                group.finish();
            }
        }
    }
}

// ============================================================================
// MULTI-ENGINE TTS THROUGHPUT BENCHMARKS
//
// Covers all engine types available in the registry. Engines are divided into:
//
//  A) REAL neural inference (model weights required):
//     - kokoro-onnx   → KokoroOnnxEngine   (ORT, no feature gate)
//     - kokoro-v1.0   → KokoroEngine       (requires `torch` feature)
//
//  B) PARAMETRIC synthesis stubs (no model files needed):
//     - bark          → BarkEngine         (multi-harmonic prosody model)
//     - styletts2     → StyleTTS2Engine    (emotional prosody, 5 harmonics)
//     - xtts-v2       → XTTSEngine        (formant synthesis, 16 languages)
//     - vits          → VITSEngine        (VITS-style parametric)
//
//  Stub engines are useful for:
//    • Benchmarking engine interface overhead (serialization, async dispatch)
//    • Validating that throughput scales linearly with text length
//    • Regression testing without GPU/large downloads
//
//  Registry models that need custom Python/Rust inference engines
//  (F5-TTS, Parler-TTS, OuteTTS, Chatterbox, Sesame-CSM, CosyVoice2, etc.)
//  are listed in model_registry.json for server-side download; benchmarks
//  for these will be added as their Rust engines are implemented.
// ============================================================================

/// Defines one TTS engine entry for the stub benchmark.
struct StubEngineEntry {
    label: &'static str,
    /// Registry model ID (informational)
    registry_id: &'static str,
    /// Voice to use in by-voice group
    voice: &'static str,
    engine: Box<dyn torch_inference::core::tts_engine::TTSEngine>,
}

fn make_stub_entries() -> Vec<StubEngineEntry> {
    use torch_inference::core::bark_tts::BarkEngine;
    use torch_inference::core::vits_tts::VITSEngine;
    use torch_inference::core::styletts2::StyleTTS2Engine;
    use torch_inference::core::xtts::XTTSEngine;

    let mut entries = Vec::new();

    if let Ok(e) = BarkEngine::new(&serde_json::json!({"sample_rate": 24000})) {
        entries.push(StubEngineEntry {
            label: "bark",
            registry_id: "bark",
            voice: "en_speaker_0",
            engine: Box::new(e),
        });
    }
    if let Ok(e) = StyleTTS2Engine::new(&serde_json::json!({"sample_rate": 24000})) {
        entries.push(StubEngineEntry {
            label: "styletts2",
            registry_id: "styletts2",
            voice: "en_US_default",
            engine: Box::new(e),
        });
    }
    if let Ok(e) = XTTSEngine::new(&serde_json::json!({"sample_rate": 24000})) {
        entries.push(StubEngineEntry {
            label: "xtts-v2",
            registry_id: "xtts-v2",
            voice: "en",
            engine: Box::new(e),
        });
    }
    if let Ok(e) = VITSEngine::new(&serde_json::json!({"sample_rate": 22050})) {
        entries.push(StubEngineEntry {
            label: "vits",
            registry_id: "vits-vctk",
            voice: "en_US_default",
            engine: Box::new(e),
        });
    }

    entries
}

fn benchmark_tts_engines(c: &mut Criterion) {
    use torch_inference::core::tts_engine::{TTSEngine, SynthesisParams};
    use criterion::Throughput;

    let rt = tokio::runtime::Runtime::new().unwrap();
    let entries = make_stub_entries();

    if entries.is_empty() {
        println!("No stub TTS engines available");
        return;
    }

    // --- Chars/sec across text lengths ---
    for entry in &entries {
        let mut group = c.benchmark_group(format!("tts_throughput/{}", entry.label));
        group.sample_size(50);
        group.measurement_time(Duration::from_secs(30));

        for &(text_label, text) in TTS_TEXTS {
            group.throughput(Throughput::Bytes(text.len() as u64));
            let params = SynthesisParams {
                voice: Some(entry.voice.to_string()),
                speed: 1.0, pitch: 1.0, language: None,
            };
            group.bench_with_input(
                BenchmarkId::new("chars_per_sec", text_label),
                &text,
                |b, txt| {
                    b.iter(|| rt.block_on(async {
                        black_box(entry.engine.synthesize(txt, &params).await.ok())
                    }));
                },
            );
        }
        group.finish();
    }

    // --- Words/sec (RTF proxy) ---
    for entry in &entries {
        let mut group = c.benchmark_group(format!("tts_rtf/{}", entry.label));
        group.sample_size(50);
        group.measurement_time(Duration::from_secs(30));

        for &(text_label, text) in TTS_TEXTS {
            let wc = text.split_whitespace().count() as u64;
            group.throughput(Throughput::Elements(wc));
            let params = SynthesisParams {
                voice: Some(entry.voice.to_string()),
                speed: 1.0, pitch: 1.0, language: None,
            };
            group.bench_with_input(
                BenchmarkId::new("words_per_sec", text_label),
                &text,
                |b, txt| {
                    b.iter(|| rt.block_on(async {
                        black_box(entry.engine.synthesize(txt, &params).await.ok())
                    }));
                },
            );
        }
        group.finish();
    }

    // --- Cross-engine comparison at medium text ---
    {
        let mut group = c.benchmark_group("tts_engine_comparison");
        group.sample_size(50);
        group.measurement_time(Duration::from_secs(30));

        let text = TTS_TEXTS[1].1; // medium
        group.throughput(Throughput::Bytes(text.len() as u64));

        for entry in &entries {
            let params = SynthesisParams {
                voice: Some(entry.voice.to_string()),
                speed: 1.0, pitch: 1.0, language: None,
            };
            group.bench_with_input(
                BenchmarkId::new("engine", entry.label),
                &entry.label,
                |b, _| {
                    b.iter(|| rt.block_on(async {
                        black_box(entry.engine.synthesize(text, &params).await.ok())
                    }));
                },
            );
        }
        group.finish();
    }

    // --- Speed scale test (0.5×, 1.0×, 2.0×) on medium text ---
    for entry in &entries {
        let mut group = c.benchmark_group(format!("tts_speed_scale/{}", entry.label));
        group.sample_size(50);
        group.measurement_time(Duration::from_secs(20));

        let text = TTS_TEXTS[1].1;
        group.throughput(Throughput::Bytes(text.len() as u64));

        for &speed in &[0.5f32, 1.0, 2.0] {
            let params = SynthesisParams {
                voice: Some(entry.voice.to_string()),
                speed,
                pitch: 1.0,
                language: None,
            };
            group.bench_with_input(
                BenchmarkId::new("speed", format!("{:.1}x", speed)),
                &speed,
                |b, _| {
                    b.iter(|| rt.block_on(async {
                        black_box(entry.engine.synthesize(text, &params).await.ok())
                    }));
                },
            );
        }
        group.finish();
    }
}

criterion_group!(
    benches,
    benchmark_model_loading,
    benchmark_image_preprocessing,
    benchmark_image_classification,
    benchmark_batch_inference,
    benchmark_memory_usage,
    benchmark_model_download_time,
    benchmark_tts_throughput,
    benchmark_tts_onnx_throughput,
    benchmark_tts_engines
);
criterion_main!(benches);

// Build script for torch-inference
// Handles automatic PyTorch library detection, download, and setup
// Integrates functionality from build.sh for comprehensive build automation

use std::env;
use std::fs;
use std::path::PathBuf;
use std::process::Command;

fn main() {
    println!("cargo:rerun-if-changed=build.rs");
    println!("cargo:rerun-if-env-changed=LIBTORCH");
    println!("cargo:rerun-if-env-changed=LIBTORCH_DIR");
    println!("cargo:rerun-if-env-changed=CUDA_PATH");
    println!("cargo:rerun-if-env-changed=LIBTORCH_USE_PYTORCH");

    print_header();

    // Detect system configuration
    let system_info = detect_system();
    print_system_info(&system_info);

    // Check if torch feature is enabled
    if !cfg!(feature = "torch") {
        println!("cargo:warning=[INFO] PyTorch feature not enabled. Skipping libtorch setup.");
        return;
    }

    println!("cargo:warning=[INFO] Checking for PyTorch (libtorch) installation...");

    // Try to find existing libtorch
    if let Some(libtorch_path) = find_libtorch() {
        println!("cargo:warning=[OK] Found libtorch at: {:?}", libtorch_path);
        setup_libtorch_paths(&libtorch_path, &system_info);
    } else {
        println!("cargo:warning=[WARN] LibTorch not found - attempting auto-download...");

        // Try to auto-download libtorch
        match auto_download_libtorch(&system_info) {
            Ok(libtorch_path) => {
                println!("cargo:warning=[OK] Successfully downloaded libtorch to: {:?}", libtorch_path);
                setup_libtorch_paths(&libtorch_path, &system_info);
            }
            Err(e) => {
                println!("cargo:warning=[WARN] Failed to auto-download libtorch: {}", e);
                print_manual_instructions();
                println!("cargo:rustc-cfg=libtorch_unavailable");
            }
        }
    }

    // Check for additional features
    check_cuda_support(&system_info);
    check_metal_support(&system_info);
    check_onnx_support();
}

fn print_header() {
    println!("cargo:warning=");
    println!("cargo:warning=╔══════════════════════════════════════════════════════════╗");
    println!("cargo:warning=║    PyTorch Inference Framework - Build Configuration    ║");
    println!("cargo:warning=╚══════════════════════════════════════════════════════════╝");
    println!("cargo:warning=");
}

struct SystemInfo {
    os: String,
    arch: String,
    has_cuda: bool,
    has_metal: bool,
    cuda_version: Option<String>,
}

fn detect_system() -> SystemInfo {
    let os = env::var("CARGO_CFG_TARGET_OS").unwrap_or_else(|_| "unknown".to_string());
    let arch = env::var("CARGO_CFG_TARGET_ARCH").unwrap_or_else(|_| "unknown".to_string());

    // Check for CUDA
    let has_cuda = check_cuda_available();
    let cuda_version = if has_cuda {
        get_cuda_version()
    } else {
        None
    };

    // Check for Metal (Apple Silicon)
    let has_metal = os == "macos" && (arch == "aarch64" || arch == "arm64");

    SystemInfo {
        os,
        arch,
        has_cuda,
        has_metal,
        cuda_version,
    }
}

fn print_system_info(info: &SystemInfo) {
    println!("cargo:warning=[INFO] System Configuration:");
    println!("cargo:warning=   OS: {}", info.os);
    println!("cargo:warning=   Architecture: {}", info.arch);
    println!("cargo:warning=   CUDA: {}", if info.has_cuda { 
        format!("Available ({})", info.cuda_version.as_ref().unwrap_or(&"unknown".to_string()))
    } else { 
        "Not Available".to_string() 
    });
    println!("cargo:warning=   Metal: {}", if info.has_metal { 
        "Available (Apple Silicon)" 
    } else { 
        "Not Available" 
    });
    println!("cargo:warning=");
}

fn check_cuda_available() -> bool {
    Command::new("nvidia-smi")
        .output()
        .map(|output| output.status.success())
        .unwrap_or(false)
}

fn get_cuda_version() -> Option<String> {
    Command::new("nvidia-smi")
        .arg("--query-gpu=driver_version")
        .arg("--format=csv,noheader")
        .output()
        .ok()
        .and_then(|output| {
            String::from_utf8(output.stdout)
                .ok()
                .map(|s| s.trim().to_string())
        })
}

fn auto_download_libtorch(system_info: &SystemInfo) -> Result<PathBuf, String> {
    println!("cargo:warning=[INFO] Auto-downloading LibTorch...");

    // Determine download URL based on system
    let download_url = get_libtorch_download_url(system_info)?;

    // Determine cache directory
    let cache_dir = get_cache_dir()?;

    // For local directory, we extract directly to it
    let is_local = cache_dir == PathBuf::from(".");
    let libtorch_dir = if is_local {
        PathBuf::from("./libtorch")
    } else {
        cache_dir.join("libtorch")
    };

    // Check if already downloaded
    if validate_libtorch(&libtorch_dir) {
        println!("cargo:warning=[OK] LibTorch already cached at: {:?}", libtorch_dir);
        return Ok(libtorch_dir);
    }

    println!("cargo:warning=[INFO] Downloading from: {}", download_url);
    println!("cargo:warning=[INFO] Target directory: {:?}", if is_local { PathBuf::from("./") } else { cache_dir.clone() });

    // Create cache directory
    fs::create_dir_all(&cache_dir)
        .map_err(|e| format!("Failed to create cache directory: {}", e))?;

    // Download using curl or wget
    let archive_path = cache_dir.join("libtorch.zip");

    let download_success = if Command::new("curl").arg("--version").output().is_ok() {
        println!("cargo:warning=[INFO] Using curl for download...");
        Command::new("curl")
            .arg("-L")
            .arg("-o")
            .arg(&archive_path)
            .arg(&download_url)
            .arg("--progress-bar")
            .status()
            .map(|s| s.success())
            .unwrap_or(false)
    } else if Command::new("wget").arg("--version").output().is_ok() {
        println!("cargo:warning=[INFO] Using wget for download...");
        Command::new("wget")
            .arg("-O")
            .arg(&archive_path)
            .arg(&download_url)
            .status()
            .map(|s| s.success())
            .unwrap_or(false)
    } else {
        return Err("Neither curl nor wget found. Please install one of them.".to_string());
    };

    if !download_success {
        return Err("Download failed".to_string());
    }

    println!("cargo:warning=[INFO] Extracting LibTorch...");

    // Extract using appropriate tool based on OS
    let extract_success = if cfg!(target_os = "windows") {
        // On Windows, try PowerShell Expand-Archive
        Command::new("powershell")
            .arg("-Command")
            .arg(format!("Expand-Archive -Path '{}' -DestinationPath '{}' -Force", 
                archive_path.display(), cache_dir.display()))
            .status()
            .map(|s| s.success())
            .unwrap_or(false)
    } else {
        // On Unix-like systems, use unzip
        Command::new("unzip")
            .arg("-q")
            .arg(&archive_path)
            .arg("-d")
            .arg(&cache_dir)
            .status()
            .map(|s| s.success())
            .unwrap_or(false)
    };

    if !extract_success {
        return Err("Extraction failed. On Windows, ensure PowerShell is available. On Unix, install unzip.".to_string());
    }

    // Clean up archive
    let _ = fs::remove_file(&archive_path);

    // Verify extraction
    if validate_libtorch(&libtorch_dir) {
        println!("cargo:warning=[OK] LibTorch installed successfully");
        Ok(libtorch_dir)
    } else {
        Err("LibTorch extraction validation failed".to_string())
    }
}

fn get_libtorch_download_url(system_info: &SystemInfo) -> Result<String, String> {
    let version = "2.1.0";

    let url = match (system_info.os.as_str(), system_info.arch.as_str(), system_info.has_cuda) {
        // macOS (Intel and Apple Silicon use universal binary)
        ("macos", _, _) => {
            format!("https://download.pytorch.org/libtorch/cpu/libtorch-macos-{}.zip", version)
        }

        // Linux with CUDA
        ("linux", "x86_64", true) => {
            let cuda_ver = system_info.cuda_version.as_ref()
                .and_then(|v| {
                    // Extract major.minor from version like "535.104.05"
                    v.split('.').take(2).collect::<Vec<_>>().join(".")
                        .parse::<f32>().ok()
                        .map(|ver| {
                            if ver >= 12.0 { "cu121" }
                            else if ver >= 11.8 { "cu118" }
                            else { "cu117" }
                        })
                })
                .unwrap_or("cu118");

            format!("https://download.pytorch.org/libtorch/{}/libtorch-cxx11-abi-shared-with-deps-{}%2B{}.zip", 
                    cuda_ver, version, cuda_ver)
        }

        // Linux CPU
        ("linux", "x86_64", false) => {
            format!("https://download.pytorch.org/libtorch/cpu/libtorch-cxx11-abi-shared-with-deps-{}%2Bcpu.zip", version)
        }

        // Windows with CUDA
        ("windows", "x86_64", true) => {
            let cuda_ver = system_info.cuda_version.as_ref()
                .and_then(|v| {
                    v.split('.').take(2).collect::<Vec<_>>().join(".")
                        .parse::<f32>().ok()
                        .map(|ver| {
                            if ver >= 12.0 { "cu121" }
                            else if ver >= 11.8 { "cu118" }
                            else { "cu117" }
                        })
                })
                .unwrap_or("cu118");

            format!("https://download.pytorch.org/libtorch/{}/libtorch-win-shared-with-deps-{}%2B{}.zip", 
                    cuda_ver, version, cuda_ver)
        }

        // Windows CPU
        ("windows", "x86_64", false) => {
            format!("https://download.pytorch.org/libtorch/cpu/libtorch-win-shared-with-deps-{}%2Bcpu.zip", version)
        }

        _ => {
            return Err(format!("Unsupported platform: {} {}", system_info.os, system_info.arch));
        }
    };

    Ok(url)
}

fn get_cache_dir() -> Result<PathBuf, String> {
    // Check for explicit LIBTORCH env var
    if let Ok(dir) = env::var("LIBTORCH") {
        return Ok(PathBuf::from(dir).parent().unwrap_or(&PathBuf::from(".")).to_path_buf());
    }

    // Priority 1: Use local ./libtorch directory in project root
    let local_dir = PathBuf::from("./libtorch");
    if local_dir.exists() && validate_libtorch(&local_dir) {
        return Ok(PathBuf::from("."));
    }

    // Priority 2: Try to create local directory
    // Only use system cache if we can't use local directory
    let use_local = env::var("LIBTORCH_LOCAL").is_ok() || env::var("LIBTORCH_USE_LOCAL").is_ok();

    if use_local || !local_dir.exists() {
        // Prefer local directory for easier project portability
        return Ok(PathBuf::from("."));
    }

    // Priority 3: Use standard cache directory based on OS
    let cache_dir = if cfg!(target_os = "windows") {
        // Windows: Use %LOCALAPPDATA%\libtorch or %USERPROFILE%\.cache\libtorch
        if let Ok(local_app_data) = env::var("LOCALAPPDATA") {
            PathBuf::from(local_app_data).join("libtorch")
        } else if let Ok(userprofile) = env::var("USERPROFILE") {
            PathBuf::from(userprofile).join(".cache").join("libtorch")
        } else {
            PathBuf::from(".")
        }
    } else if cfg!(target_os = "macos") {
        // macOS: Use ~/Library/Caches/libtorch or ~/.cache/libtorch
        if let Ok(home) = env::var("HOME") {
            let library_cache = PathBuf::from(&home).join("Library").join("Caches").join("libtorch");
            if library_cache.parent().map(|p| p.exists()).unwrap_or(false) {
                library_cache
            } else {
                PathBuf::from(home).join(".cache").join("libtorch")
            }
        } else {
            PathBuf::from(".")
        }
    } else {
        // Linux: Use ~/.cache/libtorch
        if let Ok(home) = env::var("HOME") {
            PathBuf::from(home).join(".cache").join("libtorch")
        } else {
            PathBuf::from(".")
        }
    };

    Ok(cache_dir)
}

fn find_libtorch() -> Option<PathBuf> {
    // Method 1: Check LIBTORCH environment variable
    if let Ok(libtorch) = env::var("LIBTORCH") {
        let path = PathBuf::from(&libtorch);
        if validate_libtorch(&path) {
            println!("cargo:warning=[OK] Found via LIBTORCH env: {}", libtorch);
            return Some(path);
        }
    }

    // Method 2: Check LIBTORCH_DIR environment variable
    if let Ok(libtorch_dir) = env::var("LIBTORCH_DIR") {
        let path = PathBuf::from(&libtorch_dir);
        if validate_libtorch(&path) {
            println!("cargo:warning=[OK] Found via LIBTORCH_DIR env: {}", libtorch_dir);
            return Some(path);
        }
    }

    // Method 3: Check cache directory
    if let Ok(cache_dir) = get_cache_dir() {
        let cached_path = cache_dir.join("libtorch");
        if validate_libtorch(&cached_path) {
            println!("cargo:warning=[OK] Found in cache: {:?}", cached_path);
            return Some(cached_path);
        }
    }

    // Method 4: Check default installation directory
    let default_path = PathBuf::from("./libtorch");
    if validate_libtorch(&default_path) {
        println!("cargo:warning=[OK] Found in local directory");
        return Some(default_path);
    }

    // Method 5: Check common installation paths
    let common_paths = vec![
        "/usr/local/libtorch",
        "/opt/libtorch",
        "C:\\libtorch",
        "C:\\Program Files\\libtorch",
    ];

    for path_str in common_paths {
        let path = PathBuf::from(path_str);
        if validate_libtorch(&path) {
            println!("cargo:warning=[OK] Found at: {}", path_str);
            return Some(path);
        }
    }

    // Method 6: Try to use PyTorch's libtorch (if LIBTORCH_USE_PYTORCH is set)
    if env::var("LIBTORCH_USE_PYTORCH").is_ok() {
        if let Some(path) = find_pytorch_libtorch() {
            println!("cargo:warning=[OK] Using PyTorch's libtorch");
            return Some(path);
        }
    }

    None
}

fn find_pytorch_libtorch() -> Option<PathBuf> {
    // Try to find PyTorch installation and get libtorch path
    let output = Command::new("python3")
        .args(&["-c", "import torch; print(torch.__path__[0])"])
        .output()
        .ok()?;

    if output.status.success() {
        let torch_path = String::from_utf8(output.stdout).ok()?;
        let libtorch_path = PathBuf::from(torch_path.trim()).join("lib");

        if validate_libtorch(&libtorch_path) {
            return Some(libtorch_path);
        }
    }

    None
}

fn validate_libtorch(path: &PathBuf) -> bool {
    if !path.exists() {
        return false;
    }

    let lib_dir = path.join("lib");
    let include_dir = path.join("include");

    if !lib_dir.exists() || !include_dir.exists() {
        return false;
    }

    // Check for torch library
    #[cfg(target_os = "windows")]
    let torch_lib = lib_dir.join("torch.lib");

    #[cfg(target_os = "linux")]
    let torch_lib = lib_dir.join("libtorch.so");

    #[cfg(target_os = "macos")]
    let torch_lib = lib_dir.join("libtorch.dylib");

    torch_lib.exists()
}

fn setup_libtorch_paths(libtorch_path: &PathBuf, system_info: &SystemInfo) {
    let lib_path = libtorch_path.join("lib");

    println!("cargo:warning=[INFO] Configuring LibTorch paths...");

    // Set LIBTORCH environment variable for torch-sys
    println!("cargo:rustc-env=LIBTORCH={}", libtorch_path.display());

    // Set linker paths
    println!("cargo:rustc-link-search=native={}", lib_path.display());

    // Link core libraries
    println!("cargo:rustc-link-lib=dylib=torch");
    println!("cargo:rustc-link-lib=dylib=torch_cpu");
    println!("cargo:rustc-link-lib=dylib=c10");

    println!("cargo:warning=[OK] Core libraries linked");

    // Check for CUDA libraries
    let has_cuda_lib = if cfg!(target_os = "windows") {
        lib_path.join("torch_cuda.dll").exists()
    } else {
        lib_path.join("libtorch_cuda.so").exists() || 
        lib_path.join("libtorch_cuda.dylib").exists()
    };

    if has_cuda_lib {
        println!("cargo:rustc-link-lib=dylib=torch_cuda");
        println!("cargo:rustc-cfg=has_cuda");
        println!("cargo:warning=[OK] CUDA support enabled in libtorch");
    }

    // Check for Metal/MPS support (macOS)
    if system_info.has_metal {
        let has_mps = lib_path.join("libtorch_mps.dylib").exists();
        if has_mps {
            println!("cargo:rustc-cfg=has_metal");
            println!("cargo:warning=[OK] Metal (MPS) support enabled");
        }
    }

    // Set runtime library paths
    #[cfg(target_os = "linux")]
    {
        println!("cargo:rustc-env=LD_LIBRARY_PATH={}", lib_path.display());
    }

    #[cfg(target_os = "macos")]
    {
        println!("cargo:rustc-env=DYLD_LIBRARY_PATH={}", lib_path.display());
        println!("cargo:rustc-env=DYLD_FALLBACK_LIBRARY_PATH={}", lib_path.display());
    }

    #[cfg(target_os = "windows")]
    {
        println!("cargo:rustc-env=PATH={}", lib_path.display());
    }

    // Output library information
    println!("cargo:warning=[INFO] LibTorch configuration:");
    println!("cargo:warning=   Library path: {}", lib_path.display());
    println!("cargo:warning=   CUDA: {}", if has_cuda_lib { "Enabled" } else { "Disabled" });
    println!("cargo:warning=   Metal: {}", if system_info.has_metal { "Available" } else { "Not Available" });
}

fn check_cuda_support(system_info: &SystemInfo) {
    if cfg!(feature = "cuda") {
        if system_info.has_cuda {
            println!("cargo:rustc-cfg=cuda_enabled");
            println!("cargo:warning=[OK] CUDA feature enabled");
        } else {
            println!("cargo:warning=[WARN] CUDA feature enabled but CUDA not found");
        }
    }
}

fn check_metal_support(system_info: &SystemInfo) {
    if system_info.has_metal {
        println!("cargo:rustc-cfg=metal_available");
        println!("cargo:warning=[OK] Metal GPU acceleration available");
    }
}

fn check_onnx_support() {
    if cfg!(feature = "onnx") {
        println!("cargo:warning=[INFO] ONNX Runtime feature enabled");
    }
}

