    // ---- load_audio mp3/flac/ogg routing (lines 181-183) via valid data ---
    // Build a minimal valid FLAC stream so probe_metadata_with_symphonia
    // (lines 121-159) and load_with_symphonia (lines 214-268) are reached.

    /// Build the smallest valid FLAC file: a STREAMINFO-only file with 0 frames.
    /// Layout: "fLaC" marker + last STREAMINFO metadata block + 34-byte payload.
    fn make_minimal_flac_bytes() -> Vec<u8> {
        let mut v = Vec::with_capacity(46);
        // FLAC stream marker
        v.extend_from_slice(b"fLaC");
        // Metadata block header: last=1 (bit7), type=STREAMINFO=0 → 0x80
        // Length = 34 bytes → 0x000022
        v.extend_from_slice(&[0x80, 0x00, 0x00, 0x22]);
        // STREAMINFO payload (34 bytes):
        // min_blocksize (16-bit BE): 4096 = 0x1000
        v.extend_from_slice(&[0x10, 0x00]);
        // max_blocksize (16-bit BE): 4096 = 0x1000
        v.extend_from_slice(&[0x10, 0x00]);
        // min_framesize (24-bit BE): 0
        v.extend_from_slice(&[0x00, 0x00, 0x00]);
        // max_framesize (24-bit BE): 0
        v.extend_from_slice(&[0x00, 0x00, 0x00]);
        // Packed: sample_rate(20) | channels-1(3) | bps-1(5) | total_samples(36)
        // sample_rate = 44100 = 0xAC44 in 20 bits: 0000_1010_1100_0100_0100
        // channels-1 = 0 (mono): 000
        // bps-1 = 15 (16-bit): 01111
        // total_samples = 0: 36 zeros
        // combined 64 bits: 0000_1010 | 1100_0100 | 0100_0000 | 0111_1000 | 0*4bytes
        v.extend_from_slice(&[0x0A, 0xC4, 0x40, 0x78, 0x00, 0x00, 0x00, 0x00]);
        // MD5 checksum (16 bytes, all zero for empty file)
        v.extend_from_slice(&[0x00u8; 16]);
        v
    }

