    // ---- probe_metadata_with_symphonia / load_with_symphonia (lines 121-159, 181-183, 214-268) ---
    //
    // Minimal Ogg Vorbis stream (2 pages: BOS identification + comment+setup).
    // Symphonia can probe this to extract format metadata (sample_rate=44100, channels=1).
    // The setup header here has no valid codebooks so decode will fail, but the probe
    // and track-discovery paths (lines 128-159) are fully exercised.
    fn make_minimal_ogg_vorbis_bytes() -> Vec<u8> {
        // Two Ogg pages forming a valid Vorbis identification + comment/setup stream.
        // sample_rate = 44100 (0xAC44 LE), channels = 1.
        // CRCs pre-computed to pass symphonia's page validation.
        vec![
            // Page 1: BOS page with Vorbis ID header
            0x4f, 0x67, 0x67, 0x53, 0x00, 0x02, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00,
            0x01, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0xf5, 0x41, 0xfe, 0xb7, 0x01,
            0x1e,
            0x01, 0x76, 0x6f, 0x72, 0x62, 0x69, 0x73, // "\x01vorbis"
            0x00, 0x00, 0x00, 0x00, // version=0
            0x01,                   // channels=1
            0x44, 0xac, 0x00, 0x00, // sample_rate=44100 (LE)
            0x00, 0x00, 0x00, 0x00, // bitrate_max=0
            0x00, 0xf4, 0x01, 0x00, // bitrate_nominal=128000
            0x00, 0x00, 0x00, 0x00, // bitrate_min=0
            0x99,                   // blocksize_0=9<<4|9
            0x01,                   // framing
            // Page 2: comment + setup headers
            0x4f, 0x67, 0x67, 0x53, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00,
            0x01, 0x00, 0x00, 0x00, 0x01, 0x00, 0x00, 0x00, 0xd9, 0x80, 0x7f, 0xd5, 0x01,
            0x1b,
            0x03, 0x76, 0x6f, 0x72, 0x62, 0x69, 0x73, // "\x03vorbis" (comment)
            0x04, 0x00, 0x00, 0x00, 0x74, 0x65, 0x73, 0x74, // vendor="test"
            0x00, 0x00, 0x00, 0x00, // user_comment_list_length=0
            0x05, 0x76, 0x6f, 0x72, 0x62, 0x69, 0x73, // "\x05vorbis" (setup)
            0x01,                   // framing
        ]
    }

