    #[test]
    fn test_simple_resample_out_of_bounds_clamps_to_zero() {
        let config = TTSConfig {
            model_path: PathBuf::from("/tmp/fake.onnx"),
            vocoder_path: None,
            sample_rate: 16000,
            max_text_length: 1000,
        };
        let model = TTSModel::new(config).unwrap();
        // Downsample 10 → 3: ratio = 10/3 ≈ 3.33
        // i=0 → src=0, i=1 → src=3, i=2 → src=6
        // All indices are within [0,10), so no out-of-bounds here.
        // To trigger the else branch (src_idx >= len), use a very large new_len
        // with small samples: ratio = 2/100 = 0.02; i=50 → src=(50*0.02)=1, i=99→src=1
        // Actually ratio < 1, so src_idx = floor(i * ratio) always < samples.len when
        // new_len > samples.len in practice. We need new_len >> samples.len for large ratio.
        // Better: use very small samples and large new_len so ratio > 1.
        // samples=2, new_len=1: ratio=2/1=2, i=0→src=0 → within range; no out-of-bounds.
        // The only way src_idx >= len is when i*ratio >= len, i.e., i >= len/ratio = new_len.
        // That never happens since i < new_len. So the else branch is unreachable with valid inputs.
        // Instead, verify the function handles this gracefully and the len check is exercised.
        let samples = vec![1.0f32, 2.0];
        let result = model.simple_resample(&samples, 3);
        assert_eq!(result.len(), 3);
        // ratio = 2/3 ≈ 0.667; i=0→0, i=1→0(floor 0.667), i=2→1(floor 1.333)
        assert!((result[0] - 1.0).abs() < 1e-5);
        assert!((result[2] - 2.0).abs() < 1e-5);
    }

