/// Misaki-compatible G2P converter
pub struct MisakiG2P {
    pub vocab: &'static HashMap<String, i64>,
    dict: &'static HashMap<&'static str, &'static str>,
}

impl MisakiG2P {
    pub fn new() -> Result<Self> {
        Ok(Self {
            vocab: &PHONEME_VOCAB,
            dict: &PRONUNCIATION_DICT,
        })
    }

    /// Convert text to phoneme token IDs.
    /// Replicates what Python misaki + KModel.forward() does:
    ///   text -> IPA phoneme string -> character-by-character vocab lookup -> i64 IDs
    pub fn text_to_tokens(&self, text: &str) -> Result<Vec<i64>> {
        log::debug!("Converting text to phonemes: '{}'", text);

        let mut tokens = Vec::new();
        let normalized = text.trim().to_lowercase();
        let words = self.tokenize(&normalized);

        for (i, word) in words.iter().enumerate() {
            if i > 0 && !self.is_punctuation(word) {
                if let Some(&t) = self.vocab.get(" ") {
                    tokens.push(t);
                }
            }

            if self.is_punctuation(word) {
                if let Some(&t) = self.vocab.get(word.as_str()) {
                    tokens.push(t);
                }
            } else {
                let word_tokens = self.word_to_tokens(word)?;
                tokens.extend(word_tokens);
            }
        }

        // Add trailing period if sentence doesn't end with punctuation
        if tokens.last().map(|&t| t != 4).unwrap_or(true) {
            if let Some(&period) = self.vocab.get(".") {
                tokens.push(period);
            }
        }

        log::debug!("Generated {} phoneme tokens", tokens.len());
        Ok(tokens)
    }

    fn tokenize(&self, text: &str) -> Vec<String> {
        let mut result = Vec::new();
        let mut current = String::new();

        for ch in text.chars() {
            if ch.is_alphabetic() || ch == '\'' {
                current.push(ch);
            } else {
                if !current.is_empty() {
                    result.push(current.clone());
                    current.clear();
                }
                if !ch.is_whitespace() {
                    result.push(ch.to_string());
                }
            }
        }
        if !current.is_empty() {
            result.push(current);
        }
        result
    }

    fn is_punctuation(&self, s: &str) -> bool {
        let mut chars = s.chars();
        if let Some(ch) = chars.next() {
            chars.next().is_none() && !ch.is_alphanumeric()
        } else {
            false
        }
    }

    fn word_to_tokens(&self, word: &str) -> Result<Vec<i64>> {
        if let Some(&ipa) = self.dict.get(word) {
            return self.phoneme_string_to_tokens(ipa);
        }
        // Fallback: letter-level approximation
        self.letter_fallback(word)
    }

    /// Convert a Kokoro IPA phoneme string to token IDs.
    /// The string is processed character-by-character (Unicode scalar values),
    /// exactly matching KModel.forward(): vocab.get(p) for p in phonemes
    fn phoneme_string_to_tokens(&self, ipa: &str) -> Result<Vec<i64>> {
        let mut tokens = Vec::new();
        for ch in ipa.chars() {
            let s = ch.to_string();
            if let Some(&id) = self.vocab.get(&s) {
                tokens.push(id);
            } else {
                log::debug!("phoneme_string_to_tokens: no token for {:?} (U+{:04X})", s, ch as u32);
            }
        }
        Ok(tokens)
    }

    /// Letter-level fallback for unknown words.
    /// Uses simple English grapheme-to-phoneme rules with correct Kokoro IPA chars.
    fn letter_fallback(&self, word: &str) -> Result<Vec<i64>> {
        let mut tokens = Vec::new();
        for ch in word.chars() {
            // Map each letter to a plausible Kokoro phoneme character
            let ipa: &str = match ch {
                'a' => "æ",       // ɑ/æ — use æ as default
                'e' => "ɛ",
                'i' => "ɪ",
                'o' => "ɔ",
                'u' => "ʌ",
                'b' => "b",
                'c' => "k",
                'd' => "d",
                'f' => "f",
                'g' => "ɡ",      // ɡ (U+0261, not ASCII g)
                'h' => "h",
                'j' => "ʤ",
                'k' => "k",
                'l' => "l",
                'm' => "m",
                'n' => "n",
                'p' => "p",
                'q' => "k",
                'r' => "ɹ",      // American English r
                's' => "s",
                't' => "t",
                'v' => "v",
                'w' => "w",
                'x' => "ks",
                'y' => "j",
                'z' => "z",
                _ => continue,
            };
            // Handle 'ks' for 'x' (two phonemes)
            for sub_ch in ipa.chars() {
                let s = sub_ch.to_string();
                if let Some(&id) = self.vocab.get(&s) {
                    tokens.push(id);
                }
            }
        }
        Ok(tokens)
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_hello_world_correct_tokens() {
        let g2p = MisakiG2P::new().unwrap();
        // "hello" -> "həlˈO": h=50 ə=83 l=54 ˈ=156 O=31
        // " " -> 16
        // "world" -> "wˈɜɹld": w=65 ˈ=156 ɜ=87 ɹ=123 l=54 d=46
        // "." -> 4
        let tokens = g2p.text_to_tokens("hello world").unwrap();
        assert_eq!(tokens, vec![50, 83, 54, 156, 31, 16, 65, 156, 87, 123, 54, 46, 4]);
    }

    #[test]
    fn test_hello_tokens() {
        let g2p = MisakiG2P::new().unwrap();
        // "hello" -> "həlˈO" -> [50,83,54,156,31] then "." -> 4
        let tokens = g2p.text_to_tokens("hello").unwrap();
        assert_eq!(tokens, vec![50, 83, 54, 156, 31, 4]);
    }

    #[test]
    fn test_vocab_completeness() {
        let g2p = MisakiG2P::new().unwrap();
        // Key symbols that appear in common English phonemes
        let required = [
            ("ɹ", 123), ("ə", 83), ("ɪ", 102), ("ɛ", 86), ("æ", 72),
            ("ɑ", 69), ("ɔ", 76), ("ʊ", 135), ("ʌ", 138), ("ɜ", 87),
            ("ð", 81), ("θ", 119), ("ŋ", 112), ("ʃ", 131), ("ʒ", 147),
            ("ʧ", 133), ("ʤ", 82), ("ɡ", 92),
            ("ˈ", 156), ("ˌ", 157),
            (" ", 16),
            ("A", 24), ("I", 25), ("O", 31), ("W", 39), ("Y", 41),
            ("T", 36),
        ];
        for (sym, expected_id) in required {
            let id = g2p.vocab.get(sym).copied();
            assert_eq!(id, Some(expected_id), "Wrong/missing token for {:?}", sym);
        }
    }

    #[test]
    fn test_all_tokens_in_valid_range() {
        let g2p = MisakiG2P::new().unwrap();
        let sentences = [
            "hello world",
            "the quick brown fox jumps over the lazy dog",
            "testing speech synthesis",
            "how are you today",
        ];
        for s in sentences {
            let tokens = g2p.text_to_tokens(s).unwrap();
            assert!(!tokens.is_empty(), "Empty tokens for: {}", s);
            for &t in &tokens {
                assert!(t >= 1 && t <= 177, "Token {} out of range for sentence: {}", t, s);
            }
        }
    }

    #[test]
    fn test_letter_fallback_valid_tokens() {
        let g2p = MisakiG2P::new().unwrap();
        // Unknown word - exercises letter fallback
        let tokens = g2p.text_to_tokens("xylophone").unwrap();
        for &t in &tokens {
            assert!(t >= 1 && t <= 177, "Fallback token {} out of range", t);
        }
    }

    // ---- Additional coverage for uncovered paths ----------------------

    #[test]
    fn test_empty_string_produces_period() {
        let g2p = MisakiG2P::new().unwrap();
        // Empty text: no words → tokens is empty before trailing "."
        // The implementation adds a trailing "." when tokens.last() != Some(&4)
        let tokens = g2p.text_to_tokens("").unwrap();
        // period token (4) should be the last (and only) token
        assert_eq!(tokens, vec![4]);
    }

    #[test]
    fn test_sentence_ending_with_period_no_duplicate() {
        let g2p = MisakiG2P::new().unwrap();
        // A sentence that already ends with "." should not get a second period
        let tokens = g2p.text_to_tokens("hello.").unwrap();
        // Last two tokens must not both be 4
        if tokens.len() >= 2 {
            assert!(
                !(tokens[tokens.len() - 1] == 4 && tokens[tokens.len() - 2] == 4),
                "duplicate period found: {:?}", tokens
            );
        }
    }

    #[test]
    fn test_punctuation_only() {
        let g2p = MisakiG2P::new().unwrap();
        let tokens = g2p.text_to_tokens("!").unwrap();
        // "!" → token 5 in vocab; no space before first word
        assert!(tokens.contains(&5));
    }

    #[test]
    fn test_multiple_punctuation() {
        let g2p = MisakiG2P::new().unwrap();
        let tokens = g2p.text_to_tokens("hello, world!").unwrap();
        assert!(!tokens.is_empty());
        // comma (3) should appear
        assert!(tokens.contains(&3), "comma token missing: {:?}", tokens);
        // exclamation (5) should appear
        assert!(tokens.contains(&5), "! token missing: {:?}", tokens);
    }

    #[test]
    fn test_is_punctuation_via_text_to_tokens() {
        let g2p = MisakiG2P::new().unwrap();
        // Punctuation token must NOT get a space prepended (is_punctuation returns true)
        let tokens_word_punct = g2p.text_to_tokens("hi,").unwrap();
        // If comma got a space before it, space token 16 would appear between "hi" phonemes and ","
        // Just verify no crash and tokens are valid
        for &t in &tokens_word_punct {
            assert!(t >= 1 && t <= 177, "token {} out of range", t);
        }
    }

    #[test]
    fn test_tokenize_apostrophe() {
        let g2p = MisakiG2P::new().unwrap();
        // Apostrophe is kept as part of the word in tokenize()
        let tokens = g2p.text_to_tokens("don't").unwrap();
        assert!(!tokens.is_empty());
        for &t in &tokens {
            assert!(t >= 1 && t <= 177, "token {} out of range", t);
        }
    }

    #[test]
    fn test_phoneme_string_to_tokens_unknown_char_skipped() {
        let g2p = MisakiG2P::new().unwrap();
        // A word whose IPA representation contains a character not in the vocab
        // should silently skip that character. Exercise via a word not in the dict.
        // 'ß' is not in PHONEME_VOCAB; the fallback letter_fallback() also skips it.
        let tokens = g2p.text_to_tokens("ßtest").unwrap();
        // Just must not panic; tokens for 't','e','s','t' should appear
        assert!(!tokens.is_empty());
    }

    #[test]
    fn test_letter_fallback_x_produces_ks() {
        let g2p = MisakiG2P::new().unwrap();
        // 'x' maps to "ks" (two chars) in letter_fallback
        // Use a word not in the dictionary that starts with 'x'
        let tokens = g2p.text_to_tokens("xray").unwrap();
        // k token = 53; s token = 61 — both should appear
        assert!(tokens.contains(&53) || tokens.contains(&61),
            "expected k(53) or s(61) from 'x' expansion: {:?}", tokens);
    }

    #[test]
    fn test_number_words_all_produce_tokens() {
        let g2p = MisakiG2P::new().unwrap();
        for word in ["one", "two", "three", "four", "five",
                     "six", "seven", "eight", "nine", "ten"] {
            let tokens = g2p.text_to_tokens(word).unwrap();
            assert!(!tokens.is_empty(), "empty tokens for '{}'", word);
            for &t in &tokens {
                assert!(t >= 1 && t <= 177, "token {} out of range for '{}'", t, word);
            }
        }
    }

    #[test]
    fn test_space_not_prepended_to_first_word() {
        let g2p = MisakiG2P::new().unwrap();
        let tokens = g2p.text_to_tokens("hello").unwrap();
        // Space token is 16; it must NOT be the first token
        assert_ne!(tokens[0], 16, "space should not be first token: {:?}", tokens);
    }

    #[test]
    fn test_space_inserted_between_words() {
        let g2p = MisakiG2P::new().unwrap();
        let tokens = g2p.text_to_tokens("hello world").unwrap();
        assert!(tokens.contains(&16), "space token (16) missing: {:?}", tokens);
    }

    // ── Additional coverage for uncovered letter_fallback arms and branches ────

    #[test]
    fn test_letter_fallback_all_vowels() {
        // Covers the 'i', 'o', 'u' arms in letter_fallback (lines 505-507)
        let g2p = MisakiG2P::new().unwrap();
        // "biou" is not in the dictionary so it goes through letter_fallback
        // Each letter maps: b→b(44), i→ɪ(102), o→ɔ(76), u→ʌ(138)
        let tokens = g2p.text_to_tokens("biou").unwrap();
        // All tokens should be in valid range; expect at least one vowel phoneme
        assert!(!tokens.is_empty());
        for &t in &tokens {
            assert!(t >= 1 && t <= 177, "token {} out of range", t);
        }
        // b → "b" (44) should appear
        assert!(tokens.contains(&44), "expected b(44): {:?}", tokens);
        // ɪ (102), ɔ (76), ʌ (138) for i, o, u
        assert!(tokens.contains(&102) || tokens.contains(&76) || tokens.contains(&138),
            "expected vowel phoneme tokens: {:?}", tokens);
    }

    #[test]
    fn test_letter_fallback_remaining_consonants() {
        // Covers arms: b(44), c→k(53), d(46), f(48), g→ɡ(92), h(50), j→ʤ(82),
        //              k(53), l(54), m(55), n(56), p(58), q→k(53), r→ɹ(123),
        //              s(61), t(62), v(64), w(65), y→j(52), z(68)
        let g2p = MisakiG2P::new().unwrap();

        // Use words not in dict to trigger fallback for each consonant
        let cases: &[(&str, i64)] = &[
            ("ccc", 53),  // c → k (53)
            ("ddd", 46),  // d → d (46)
            ("fff", 48),  // f → f (48)
            ("ggg", 92),  // g → ɡ (92)
            ("hhh", 50),  // h → h (50)
            ("jjj", 82),  // j → ʤ (82)
            ("kkk", 53),  // k → k (53)
            ("lll", 54),  // l → l (54)
            ("mmm", 55),  // m → m (55)
            ("nnn", 56),  // n → n (56)
            ("ppp", 58),  // p → p (58)
            ("qqq", 53),  // q → k (53)
            ("rrr", 123), // r → ɹ (123)
            ("sss", 61),  // s → s (61)
            ("ttt", 62),  // t → t (62)
            ("vvv", 64),  // v → v (64)
            ("www", 65),  // w → w (65)
            ("yyy", 52),  // y → j (52)
            ("zzz", 68),  // z → z (68)
        ];

        for (word, expected_token) in cases {
            let tokens = g2p.text_to_tokens(word).unwrap();
            assert!(
                tokens.contains(expected_token),
                "expected token {} for word '{}', got: {:?}",
                expected_token, word, tokens
            );
        }
    }

    #[test]
    fn test_is_punctuation_empty_string_returns_false() {
        // Exercises the `else { false }` branch (line 468) of is_punctuation()
        // is_punctuation is private, but we can trigger it via text_to_tokens
        // with an input that tokenize() produces an empty token for.
        // Actually we test it indirectly — an empty sentence creates no words,
        // so is_punctuation is never called with empty string from that path.
        // We instead verify the empty-string input behaviour is consistent.
        let g2p = MisakiG2P::new().unwrap();
        let tokens = g2p.text_to_tokens("   ").unwrap(); // whitespace only → no words
        // Only the trailing period should appear
        assert_eq!(tokens, vec![4]);
    }

    #[test]
    fn test_letter_fallback_unknown_char_skipped() {
        // The `_ => continue` arm in letter_fallback (uncovered path)
        // A character like '1' (digit) or 'ß' (non-ASCII non-vowel) hits `_ => continue`
        let g2p = MisakiG2P::new().unwrap();
        // Use a word not in dict that has a digit-like character embedded via
        // a string that the tokenizer keeps as a "word" chunk.
        // Actually tokenize() only keeps alphabetic and apostrophe chars, so
        // we need to trick it. Let's use an all-vowel unknown word with a
        // character that falls through to `_`.
        // 'ı' (U+0131, dotless i) is alphabetic but not in the match — hits `_ => continue`
        let tokens = g2p.text_to_tokens("ıı").unwrap();
        // No letter tokens produced for ı, only trailing period
        assert_eq!(tokens, vec![4], "expected only period for unknown chars: {:?}", tokens);
    }
}

use serde::{Deserialize, Serialize};
use std::sync::Arc;
use anyhow::{Result, Context};
use dashmap::DashMap;

#[derive(Debug, Clone, Serialize, Deserialize)]
pub enum GpuBackend {
    Cuda,
    Metal,
    Cpu,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct GpuInfo {
    pub available: bool,
    pub count: usize,
    pub devices: Vec<GpuDevice>,
    pub backend: GpuBackend,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct GpuDevice {
    pub id: usize,
    pub name: String,
    pub total_memory: u64,
    pub free_memory: u64,
    pub used_memory: u64,
    pub temperature: Option<u32>,
    pub utilization: Option<u32>,
    pub power_usage: Option<u32>,
    pub power_limit: Option<u32>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct GpuStats {
    pub device_id: usize,
    pub timestamp: chrono::DateTime<chrono::Utc>,
    pub memory_used: u64,
    pub memory_free: u64,
    pub utilization: u32,
    pub temperature: u32,
}

pub struct GpuManager {
    stats_history: Arc<DashMap<usize, Vec<GpuStats>>>,
    max_history: usize,
}

impl GpuManager {
    pub fn new() -> Self {
        Self {
            stats_history: Arc::new(DashMap::new()),
            max_history: 100,
        }
    }

    /// Check if Metal is available (macOS only)
    #[cfg(target_os = "macos")]
    pub fn is_metal_available() -> bool {
        use std::process::Command;

        // Check if we're on Apple Silicon or if Metal is available
        if let Ok(output) = Command::new("sysctl")
            .arg("-n")
            .arg("machdep.cpu.brand_string")
            .output()
        {
            if let Ok(cpu_info) = String::from_utf8(output.stdout) {
                // Check for Apple Silicon (M1, M2, M3, etc.)
                if cpu_info.contains("Apple") {
                    return true;
                }
            }
        }

        // Alternative: Check for Metal framework
        std::path::Path::new("/System/Library/Frameworks/Metal.framework").exists()
    }

    #[cfg(not(target_os = "macos"))]
    pub fn is_metal_available() -> bool {
        false
    }

    /// Get Metal GPU info
    #[cfg(target_os = "macos")]
    pub fn get_metal_info(&self) -> Result<GpuInfo> {
        use std::process::Command;

        log::info!("Detecting Metal GPU...");

        // Get system info
        let output = Command::new("system_profiler")
            .arg("SPDisplaysDataType")
            .output()
            .context("Failed to run system_profiler")?;

        let output_str = String::from_utf8_lossy(&output.stdout);

        // Parse GPU information
        let mut devices = Vec::new();
        let mut gpu_name = "Apple GPU".to_string();
        let mut total_memory = 0u64;

        // Try to extract GPU name and memory
        for line in output_str.lines() {
            let line = line.trim();
            if line.starts_with("Chipset Model:") {
                if let Some(name) = line.split(':').nth(1) {
                    gpu_name = name.trim().to_string();
                }
            } else if line.contains("VRAM") || line.contains("Memory") {
                // Try to extract memory size (e.g., "8 GB")
                if let Some(mem_part) = line.split(':').nth(1) {
                    let mem_str = mem_part.trim();
                    if let Some(size_str) = mem_str.split_whitespace().next() {
                        if let Ok(size) = size_str.parse::<u64>() {
                            total_memory = size * 1024 * 1024 * 1024; // Convert GB to bytes
                        }
                    }
                }
            }
        }

        // If we couldn't get specific memory, estimate based on system RAM
        if total_memory == 0 {
            // Unified memory on Apple Silicon - typically 2/3 of RAM can be used for GPU
            if let Ok(output) = Command::new("sysctl")
                .arg("-n")
                .arg("hw.memsize")
                .output()
            {
                if let Ok(mem_str) = String::from_utf8(output.stdout) {
                    if let Ok(sys_mem) = mem_str.trim().parse::<u64>() {
                        total_memory = (sys_mem * 2) / 3; // Estimate GPU can use 2/3 of system memory
                    }
                }
            }
        }

        devices.push(GpuDevice {
            id: 0,
            name: gpu_name,
            total_memory,
            free_memory: total_memory * 8 / 10, // Estimate 80% free
            used_memory: total_memory * 2 / 10, // Estimate 20% used
            temperature: None, // Metal doesn't expose temperature easily
            utilization: None, // Would need IOKit for this
            power_usage: None,
            power_limit: None,
        });

        Ok(GpuInfo {
            available: true,
            count: 1,
            devices,
            backend: GpuBackend::Metal,
        })
    }

    #[cfg(not(target_os = "macos"))]
    pub fn get_metal_info(&self) -> Result<GpuInfo> {
        Ok(GpuInfo {
            available: false,
            count: 0,
            devices: Vec::new(),
            backend: GpuBackend::Cpu,
        })
    }

    #[cfg(feature = "cuda")]
    pub fn get_info(&self) -> Result<GpuInfo> {
        use nvml_wrapper::Nvml;

        // Try CUDA first
        let nvml_result = Nvml::init();
        if nvml_result.is_err() {
            // CUDA not available, try Metal on macOS
            #[cfg(target_os = "macos")]
            {
                if Self::is_metal_available() {
                    log::info!("CUDA not available, falling back to Metal GPU");
                    return self.get_metal_info();
                }
            }

            // Return the NVML error
            return Err(nvml_result.unwrap_err().into());
        }

        let nvml = nvml_result.unwrap();
        let device_count = nvml.device_count().context("Failed to get device count")?;

        let mut devices = Vec::new();

        for i in 0..device_count {
            let device = nvml.device_by_index(i).context(format!("Failed to get device {}", i))?;

            let name = device.name().unwrap_or_else(|_| format!("GPU {}", i));
            let memory_info = device.memory_info().ok();

            let total_memory = memory_info.as_ref().map(|m| m.total).unwrap_or(0);
            let free_memory = memory_info.as_ref().map(|m| m.free).unwrap_or(0);
            let used_memory = memory_info.as_ref().map(|m| m.used).unwrap_or(0);

            let temperature = device.temperature(nvml_wrapper::enum_wrappers::device::TemperatureSensor::Gpu).ok();
            let utilization = device.utilization_rates().ok().map(|u| u.gpu);
            let power_usage = device.power_usage().ok().map(|p| p / 1000); // Convert to watts
            let power_limit = device.power_management_limit().ok().map(|p| p / 1000);

            devices.push(GpuDevice {
                id: i as usize,
                name,
                total_memory,
                free_memory,
                used_memory,
                temperature,
                utilization,
                power_usage,
                power_limit,
            });
        }

        Ok(GpuInfo {
            available: device_count > 0,
            count: device_count as usize,
            devices,
            backend: GpuBackend::Cuda,
        })
    }

    #[cfg(not(feature = "cuda"))]
    pub fn get_info(&self) -> Result<GpuInfo> {
        // On macOS, try Metal first
        #[cfg(target_os = "macos")]
        {
            if Self::is_metal_available() {
                log::info!("Detected Metal GPU, using Metal backend");
                return self.get_metal_info();
            }
        }

        // Fall back to CPU
        log::info!("No GPU detected, using CPU backend");
        Ok(GpuInfo {
            available: false,
            count: 0,
            devices: Vec::new(),
            backend: GpuBackend::Cpu,
        })
    }

    pub fn record_stats(&self, device_id: usize, stats: GpuStats) {
        let mut history = self.stats_history.entry(device_id).or_insert_with(Vec::new);
        history.push(stats);

        // Keep only recent history
        let len = history.len();
        if len > self.max_history {
            history.drain(0..(len - self.max_history));
        }
    }

    pub fn get_stats_history(&self, device_id: usize) -> Vec<GpuStats> {
        self.stats_history
            .get(&device_id)
            .map(|h| h.clone())
            .unwrap_or_default()
    }

    #[cfg(feature = "cuda")]
    pub fn collect_stats(&self) -> Result<Vec<GpuStats>> {
        use nvml_wrapper::Nvml;

        let nvml = Nvml::init()?;
        let device_count = nvml.device_count()?;
        let mut stats = Vec::new();

        for i in 0..device_count {
            if let Ok(device) = nvml.device_by_index(i) {
                let memory_info = device.memory_info().ok();
                let utilization = device.utilization_rates().ok().map(|u| u.gpu).unwrap_or(0);
                let temperature = device.temperature(nvml_wrapper::enum_wrappers::device::TemperatureSensor::Gpu).unwrap_or(0);

                let stat = GpuStats {
                    device_id: i as usize,
                    timestamp: chrono::Utc::now(),
                    memory_used: memory_info.as_ref().map(|m| m.used).unwrap_or(0),
                    memory_free: memory_info.as_ref().map(|m| m.free).unwrap_or(0),
                    utilization,
                    temperature,
                };

                self.record_stats(i as usize, stat.clone());
                stats.push(stat);
            }
        }

        Ok(stats)
    }

    #[cfg(not(feature = "cuda"))]
    pub fn collect_stats(&self) -> Result<Vec<GpuStats>> {
        // On macOS with Metal, we can collect basic stats
        #[cfg(target_os = "macos")]
        {
            if Self::is_metal_available() {
                return self.collect_metal_stats();
            }
        }
        Ok(Vec::new())
    }

    /// Collect Metal GPU statistics (macOS only)
    #[cfg(target_os = "macos")]
    pub fn collect_metal_stats(&self) -> Result<Vec<GpuStats>> {
        use std::process::Command;

        // Use system_profiler to get GPU utilization (approximate)
        let output = Command::new("system_profiler")
            .arg("SPDisplaysDataType")
            .output();

        if let Ok(output) = output {
            let output_str = String::from_utf8_lossy(&output.stdout);

            // Try to get memory info from system
            let mem_cmd = Command::new("sysctl")
                .arg("-n")
                .arg("hw.memsize")
                .output();

            let total_memory = if let Ok(mem_output) = mem_cmd {
                if let Ok(mem_str) = String::from_utf8(mem_output.stdout) {
                    mem_str.trim().parse::<u64>().unwrap_or(0)
                } else {
                    0
                }
            } else {
                0
            };

            // Estimate GPU memory (2/3 of system memory on unified architecture)
            let gpu_memory = (total_memory * 2) / 3;

            let stat = GpuStats {
                device_id: 0,
                timestamp: chrono::Utc::now(),
                memory_used: gpu_memory / 5, // Rough estimate: 20% used
                memory_free: (gpu_memory * 4) / 5, // 80% free
                utilization: 0, // Metal doesn't expose this easily
                temperature: 0, // Metal doesn't expose this easily
            };

            self.record_stats(0, stat.clone());
            return Ok(vec![stat]);
        }

        Ok(Vec::new())
    }

    #[cfg(not(target_os = "macos"))]
    pub fn collect_metal_stats(&self) -> Result<Vec<GpuStats>> {
        Ok(Vec::new())
    }

    pub fn is_cuda_available() -> bool {
        cfg!(feature = "cuda")
    }

    /// Check if CUDA is available at runtime (not just compile-time)
    #[cfg(feature = "cuda")]
    pub fn is_cuda_runtime_available() -> bool {
        use nvml_wrapper::Nvml;
        Nvml::init().is_ok()
    }

    #[cfg(not(feature = "cuda"))]
    pub fn is_cuda_runtime_available() -> bool {
        false
    }

    /// Get CUDA runtime information
    #[cfg(feature = "cuda")]
    pub fn get_cuda_info() -> Option<String> {
        use nvml_wrapper::Nvml;
        if let Ok(nvml) = Nvml::init() {
            if let Ok(count) = nvml.device_count() {
                if count > 0 {
                    if let Ok(device) = nvml.device_by_index(0) {
                        if let Ok(name) = device.name() {
                            if let Ok(driver_version) = nvml.sys_driver_version() {
                                if let Ok(cuda_version) = nvml.sys_cuda_driver_version() {
                                    return Some(format!("{} (Driver: {}, CUDA: {})", name, driver_version, cuda_version));
                                }
                            }
                        }
                    }
                }
            }
        }
        None
    }

    #[cfg(not(feature = "cuda"))]
    pub fn get_cuda_info() -> Option<String> {
        None
    }

    pub fn get_best_device(&self) -> Result<Option<usize>> {
        let info = self.get_info()?;

        if !info.available || info.devices.is_empty() {
            return Ok(None);
        }

        // Find device with most free memory
        let best = info.devices.iter()
            .max_by_key(|d| d.free_memory)
            .map(|d| d.id);

        Ok(best)
    }

    /// Get Metal runtime information (macOS only)
    #[cfg(target_os = "macos")]
    pub fn get_metal_info_string(&self) -> Option<String> {
        use std::process::Command;

        if !Self::is_metal_available() {
            return None;
        }

        // Get CPU info to determine Apple Silicon generation
        if let Ok(output) = Command::new("sysctl")
            .arg("-n")
            .arg("machdep.cpu.brand_string")
            .output()
        {
            if let Ok(cpu_info) = String::from_utf8(output.stdout) {
                let cpu_info = cpu_info.trim();

                // Get macOS version
                if let Ok(os_output) = Command::new("sw_vers")
                    .arg("-productVersion")
                    .output()
                {
                    if let Ok(os_version) = String::from_utf8(os_output.stdout) {
                        return Some(format!("{} with Metal (macOS {})", 
                            cpu_info, os_version.trim()));
                    }
                }

                return Some(format!("{} with Metal", cpu_info));
            }
        }

        Some("Apple Metal GPU".to_string())
    }

    #[cfg(not(target_os = "macos"))]
    pub fn get_metal_info_string(&self) -> Option<String> {
        None
    }
}

impl Default for GpuManager {
    fn default() -> Self {
        Self::new()
    }
}

#[cfg(test)]
mod tests {
