    }

    /// Exercises check_steganography at SecurityLevel::Maximum (threshold 0.08).
    /// A black image has all LSBs = 0 → deviation = 0.5 > 0.08 → threat.
    #[test]
    fn test_check_steganography_maximum_level_detects_deviation() {
        let validator = ImageSecurityValidator::new();
        let png = make_tiny_png(4, 4, 0, 0, 0);
        let result = validator.validate(&png, SecurityLevel::Maximum).unwrap();
        let steg: Vec<_> = result.threats_detected.iter()
            .filter(|t| matches!(t.threat_type, ThreatType::Steganography))
            .collect();
        assert!(!steg.is_empty());
    }

    /// Exercises check_steganography at SecurityLevel::High (threshold 0.10).
    #[test]
    fn test_check_steganography_high_level() {
        let validator = ImageSecurityValidator::new();
        let png = make_tiny_png(4, 4, 0, 0, 0); // all LSBs = 0, deviation = 0.5
        let result = validator.validate(&png, SecurityLevel::High).unwrap();
        let steg: Vec<_> = result.threats_detected.iter()
            .filter(|t| matches!(t.threat_type, ThreatType::Steganography))
            .collect();
        assert!(!steg.is_empty());
    }

    /// Exercises check_steganography at SecurityLevel::Medium (threshold 0.12).
    #[test]
    fn test_check_steganography_medium_level() {
        let validator = ImageSecurityValidator::new();
        let png = make_tiny_png(4, 4, 0, 0, 0);
        let result = validator.validate(&png, SecurityLevel::Medium).unwrap();
        let steg: Vec<_> = result.threats_detected.iter()
            .filter(|t| matches!(t.threat_type, ThreatType::Steganography))
            .collect();
        assert!(!steg.is_empty());
    }

    /// Verifies is_safe computation: a threat with Severity::Medium yields
    /// is_safe = true (medium/low severities are safe).
    #[test]
    fn test_validate_is_safe_with_medium_severity_threat() {
        let validator = ImageSecurityValidator::new();
        // A normal PNG might produce steganography (Low severity) and possibly
        // adversarial pattern (Medium severity) threats — both are "safe".
        let png = make_tiny_png(4, 4, 128, 64, 32);
        let result = validator.validate(&png, SecurityLevel::Low).unwrap();
        // If threats exist, they should be Low/Medium — is_safe should be true.
        let has_high_or_critical = result.threats_detected.iter()
            .any(|t| matches!(t.severity, Severity::High | Severity::Critical));
        assert!(!has_high_or_critical);
        assert!(result.is_safe);
    }

    // ── check_steganography returns None (line 262) ───────────────────────────

    /// Exercises the `None` branch of check_steganography (line 262) by
    /// creating an image whose LSB deviation is within the threshold.
    /// A 2×1 RGB image with alternating even/odd channel values gives
    /// exactly 50 % LSB=1 → deviation = 0, which is ≤ all thresholds.
    #[test]
    fn test_check_steganography_returns_none_when_lsb_balanced() {
        // Build an image where half of the raw bytes have LSB=1 and half LSB=0.
        // pixel 0: (128, 128, 128)  → LSBs = 0,0,0
        // pixel 1: (129, 129, 129)  → LSBs = 1,1,1
        // lsb_ratio = 3/6 = 0.5, deviation = 0.0 → below all thresholds → None
        let mut buf: ImageBuffer<Rgb<u8>, Vec<u8>> =
            ImageBuffer::new(2, 1);
        buf.put_pixel(0, 0, Rgb([128u8, 128, 128]));
        buf.put_pixel(1, 0, Rgb([129u8, 129, 129]));
        let img = DynamicImage::ImageRgb8(buf);

        let mut png = Vec::new();
        img.write_to(&mut std::io::Cursor::new(&mut png), image::ImageOutputFormat::Png).unwrap();

        let validator = ImageSecurityValidator::new();
        // At Low level, threshold is 0.15. With deviation = 0 the function returns None.
        let result = validator.validate(&png, SecurityLevel::Low).unwrap();
        let steg_threats: Vec<_> = result.threats_detected.iter()
            .filter(|t| matches!(t.threat_type, ThreatType::Steganography))
            .collect();
        assert!(steg_threats.is_empty(), "balanced LSB image must not trigger steganography");
    }

    /// Same balanced-LSB image at all four security levels, confirming None
    /// is returned at Medium, High, and Maximum thresholds too.
    #[test]
    fn test_check_steganography_none_all_levels() {
        // Use a larger image so LSBs stay balanced across more pixels.
        // Build a 4×2 image: rows alternate between 128 and 129 values.
        let mut buf: ImageBuffer<Rgb<u8>, Vec<u8>> = ImageBuffer::new(4, 2);
        for x in 0..4 {
            buf.put_pixel(x, 0, Rgb([128u8, 128, 128])); // LSB = 0
            buf.put_pixel(x, 1, Rgb([129u8, 129, 129])); // LSB = 1
        }
        let img = DynamicImage::ImageRgb8(buf);
        let mut png = Vec::new();
        img.write_to(&mut std::io::Cursor::new(&mut png), image::ImageOutputFormat::Png).unwrap();

        let validator = ImageSecurityValidator::new();
        for level in [SecurityLevel::Low, SecurityLevel::Medium, SecurityLevel::High, SecurityLevel::Maximum] {
            let result = validator.validate(&png, level).unwrap();
            let steg_threats: Vec<_> = result.threats_detected.iter()
                .filter(|t| matches!(t.threat_type, ThreatType::Steganography))
                .collect();
            assert!(steg_threats.is_empty(), "balanced LSB must not trigger steganography at any level");
        }
    }

    // ── validate confidence path for non-empty threats (line 145-148) ─────────

    /// When threats exist the confidence is averaged from threat confidences
    /// (lines 145-148). An ExcessiveSize threat (confidence = 1.0) is guaranteed
    /// to fire when max_file_size is tiny, ensuring the non-empty branch runs.
    #[test]
    fn test_validate_confidence_non_empty_threats() {
        let validator = ImageSecurityValidator::with_limits(8192, 1); // 1-byte limit
        let png = make_tiny_png(2, 2, 128, 128, 128);
        let result = validator.validate(&png, SecurityLevel::Low).unwrap();
        // At least the ExcessiveSize threat fires → threats non-empty → line 145-148 executes.
        assert!(!result.threats_detected.is_empty());
        // confidence = average of individual confidences; ExcessiveSize has confidence 1.0.
        let expected_avg = result.threats_detected.iter().map(|t| t.confidence).sum::<f32>()
            / result.threats_detected.len() as f32;
        assert!((result.confidence - expected_avg).abs() < 1e-5);
    }
}

/// ISTFTNet Vocoder - Convert mel-spectrogram to waveform
/// Implements a real tch::nn ISTFTNet vocoder for Kokoro TTS.
#[cfg(feature = "torch")]
use tch::{nn, nn::Module, Device, Tensor, Kind};
#[cfg(feature = "torch")]
use anyhow::Result;

// ---------------------------------------------------------------------------
// Config
// ---------------------------------------------------------------------------

#[cfg(feature = "torch")]
#[derive(Debug, Clone)]
pub struct ISTFTNetConfig {
    pub upsample_rates: Vec<i64>,
    pub upsample_kernel_sizes: Vec<i64>,
    pub resblock_kernel_sizes: Vec<i64>,
    pub resblock_dilation_sizes: Vec<Vec<i64>>,
    pub upsample_initial_channel: i64,
    pub gen_istft_n_fft: i64,
    pub gen_istft_hop_size: i64,
}

#[cfg(feature = "torch")]
impl Default for ISTFTNetConfig {
    fn default() -> Self {
        Self {
            upsample_rates: vec![10, 6],
            upsample_kernel_sizes: vec![20, 12],
            resblock_kernel_sizes: vec![3, 7, 11],
            resblock_dilation_sizes: vec![
                vec![1, 3, 5],
                vec![1, 3, 5],
                vec![1, 3, 5],
            ],
            upsample_initial_channel: 512,
            gen_istft_n_fft: 20,
            gen_istft_hop_size: 5,
        }
    }
}

// ---------------------------------------------------------------------------
// ResBlock — one residual block for the Multi-Receptive-Field Fusion (MRF)
// ---------------------------------------------------------------------------

#[cfg(feature = "torch")]
struct ResBlock {
    convs: Vec<nn::Conv1D>,
}

#[cfg(feature = "torch")]
impl ResBlock {
    fn new(vs: &nn::Path, channels: i64, kernel: i64, dilations: &[i64]) -> Self {
        let convs = dilations
            .iter()
            .map(|&d| {
                nn::conv1d(
                    vs,
                    channels,
                    channels,
                    kernel,
                    nn::ConvConfig {
                        padding: (kernel - 1) * d / 2,
                        dilation: d,
                        ..Default::default()
                    },
                )
            })
            .collect();
        Self { convs }
    }

    fn forward(&self, x: &Tensor) -> Tensor {
        let mut out = x.shallow_clone();
        for conv in &self.convs {
            out = conv.forward(&out.leaky_relu()) + &out;
        }
        out
    }
}

// ---------------------------------------------------------------------------
// ISTFTNet — the neural vocoder
// ---------------------------------------------------------------------------

#[cfg(feature = "torch")]
pub struct ISTFTNet {
    input_proj: nn::Conv1D,
    upsamplers: Vec<nn::ConvTranspose1D>,
    mrf_blocks: Vec<Vec<ResBlock>>,
    output_proj: nn::Conv1D,
    config: ISTFTNetConfig,
    device: Device,
}

#[cfg(feature = "torch")]
impl ISTFTNet {
    pub fn new(vs: &nn::Path, cfg: &ISTFTNetConfig) -> Self {
        let device = vs.device();

        // Input projection: n_mels=80 → upsample_initial_channel
        let input_proj = nn::conv1d(
            &(vs / "input_proj"),
            80,
            cfg.upsample_initial_channel,
            7,
            nn::ConvConfig {
                padding: 3,
                ..Default::default()
            },
        );

        let mut ch = cfg.upsample_initial_channel;
        let mut upsamplers = Vec::new();
        let mut mrf_blocks = Vec::new();

        for (i, (&rate, &ksize)) in cfg
            .upsample_rates
            .iter()
            .zip(cfg.upsample_kernel_sizes.iter())
            .enumerate()
        {
            let out_ch = ch / 2;
            upsamplers.push(nn::conv_transpose1d(
                &(vs / format!("up_{}", i)),
                ch,
                out_ch,
                ksize,
                nn::ConvTransposeConfig {
                    stride: rate,
                    padding: (ksize - rate) / 2,
                    ..Default::default()
                },
            ));

            // MRF: one ResBlock per kernel size
            let blocks: Vec<ResBlock> = cfg
                .resblock_kernel_sizes
                .iter()
                .zip(cfg.resblock_dilation_sizes.iter())
                .enumerate()
                .map(|(j, (&k, dilations))| {
                    ResBlock::new(
                        &(vs / format!("mrf_{}_{}", i, j)),
                        out_ch,
                        k,
                        dilations,
                    )
                })
                .collect();
            mrf_blocks.push(blocks);
            ch = out_ch;
        }

        // ch is now 128 after two upsamplers (512 → 256 → 128)
        // Output channels: (n_fft/2 + 1) * 2 for real + imag
        let out_channels = (cfg.gen_istft_n_fft / 2 + 1) * 2;
        let output_proj = nn::conv1d(
            &(vs / "output_proj"),
            ch,
            out_channels,
            1,
            Default::default(),
        );

        Self {
            input_proj,
            upsamplers,
            mrf_blocks,
            output_proj,
            config: cfg.clone(),
            device,
        }
    }

    pub fn forward(&self, mel: &Tensor) -> Tensor {
        // mel: [batch, 80, mel_frames]
        let mut x = self.input_proj.forward(mel).leaky_relu();

        for (up, mrf_stack) in self.upsamplers.iter().zip(self.mrf_blocks.iter()) {
            x = up.forward(&x.leaky_relu());
            // MRF: average across all residual block kernels
            let sum: Tensor = mrf_stack
                .iter()
                .map(|b| b.forward(&x))
                .reduce(|a, b| a + b)
                .unwrap();
            x = sum / (mrf_stack.len() as f64);
        }

        // Output projection → complex STFT representation
        let x = self.output_proj.forward(&x.leaky_relu());
        // x: [batch, (n_fft/2+1)*2, upsampled_frames]
        let batch = x.size()[0];
        let frames = x.size()[2];
        let n_bins = self.config.gen_istft_n_fft / 2 + 1;

        // x: [batch, n_bins*2, frames]
        // Split channels into [batch, 2, n_bins, frames] then apply tanh
        let stft = x.view([batch, 2, n_bins, frames]).tanh();

        // Extract real and imag components
        let real = stft.i((.., 0i64, .., ..)); // [batch, n_bins, frames]
        let imag = stft.i((.., 1i64, .., ..)); // [batch, n_bins, frames]
        let complex = Tensor::stack(&[real, imag], -1); // [batch, n_bins, frames, 2]

        // ISTFT
        let n_fft = self.config.gen_istft_n_fft;
        let hop = self.config.gen_istft_hop_size;
        let window = Tensor::hann_window(n_fft, (Kind::Float, self.device));

        complex.istft(
            n_fft,
            hop.into(),
            n_fft.into(),
            Some(&window),
            false,
            false,
            true,
            None::<i64>,
            false,
        )
        // → waveform [batch, n_samples]
    }
}

// ---------------------------------------------------------------------------
// ISTFTNetVocoder — public wrapper that owns the VarStore
// ---------------------------------------------------------------------------

#[cfg(feature = "torch")]
pub struct ISTFTNetVocoder {
    net: ISTFTNet,
    _vs: tch::nn::VarStore,
    device: Device,
}

#[cfg(feature = "torch")]
impl ISTFTNetVocoder {
    /// Create a new vocoder.
    ///
    /// * `weights_path` – optional path to a safetensors file; weights will be
    ///   partially loaded when provided and the file exists.
    /// * `device`       – computation device.
    /// * `_sample_rate` – kept for API compatibility; not used internally.
    pub fn new(
        weights_path: Option<&std::path::Path>,
        device: Device,
        _sample_rate: i64,
    ) -> Result<Self> {
        let config = ISTFTNetConfig::default();
        let mut vs = tch::nn::VarStore::new(device);
        let net = ISTFTNet::new(&(vs.root() / "vocoder"), &config);

        if let Some(path) = weights_path {
            if path.exists() {
                let unmatched = vs.load_partial(path)?;
                if !unmatched.is_empty() {
                    log::warn!(
                        "Vocoder: some registered vars not found in weights: {:?}",
                        unmatched
                    );
                }
            } else {
                log::warn!("Vocoder weights not found at {:?}, using random weights", path);
            }
        }

        Ok(Self {
            net,
            _vs: vs,
            device,
        })
    }

    /// Convert a mel-spectrogram to audio samples.
    ///
    /// `mel` is `[n_mels][n_frames]` (row-major: each inner Vec is one mel bin).
    pub fn mel_to_audio(&self, mel: &Vec<Vec<f32>>, device: Device) -> Result<Vec<f32>> {
        let n_mels = mel.len();
        let n_frames = mel
            .first()
            .ok_or_else(|| anyhow::anyhow!("empty mel-spectrogram"))?
            .len();

        let flat: Vec<f32> = mel.iter().flat_map(|r| r.iter().copied()).collect();
        let mel_tensor = Tensor::of_slice(&flat)
            .to_device(device)
            .view([1, n_mels as i64, n_frames as i64]);

        let audio = tch::no_grad(|| self.net.forward(&mel_tensor));
        let audio_cpu = audio.squeeze_dim(0).to_device(Device::Cpu);
        Ok(audio_cpu.try_into()?)
    }
}

