        // Fresh detector should have cuda_available = false, metal_available = false
        assert!(!detector.cuda_available);
        assert!(!detector.metal_available);
        assert!(detector.cuda_version.is_none());
    }

    #[test]
    fn test_autodetect_set_fields_directly() {
        let mut detector = TorchLibAutoDetect::new();
        detector.cuda_available = true;
        detector.cuda_version = Some("12.1".to_string());
        assert!(detector.cuda_available);
        assert_eq!(detector.cuda_version.as_deref(), Some("12.1"));

        detector.metal_available = true;
        assert!(detector.metal_available);
    }

    // ===== detect_cuda via CUDA_PATH that exists but has no "v" prefix (path walk) =====
    // This hits the "cuda_path.exists() is true, extract returns None" path, then
    // falls through to method 2 (versioned var loop), then method 4 (nvidia-smi).

    #[test]
    #[serial_test::serial]
    fn test_detect_cuda_path_exists_no_version_falls_through() {
        // Create a real dir but name it without "v" prefix
        let tmpdir = tempfile::TempDir::new().unwrap();
        let cuda_dir = tmpdir.path().join("cuda-no-version");
        std::fs::create_dir_all(&cuda_dir).unwrap();

        let old = env::var("CUDA_PATH").ok();
        // Clear all versioned vars too so method 2 doesn't trigger
        let saved_v12_0 = env::var("CUDA_PATH_V12_0").ok();
        env::remove_var("CUDA_PATH_V12_0");
        env::set_var("CUDA_PATH", &cuda_dir);

        let mut detector = TorchLibAutoDetect::new();
        let result = detector.detect_cuda();
        assert!(result.is_ok());
        // cuda_available depends on nvidia-smi availability (not guaranteed in CI)
        // — we just verify no panic or error

        env::remove_var("CUDA_PATH_V12_0");
        if let Some(v) = saved_v12_0 { env::set_var("CUDA_PATH_V12_0", v); }
        if let Some(v) = old { env::set_var("CUDA_PATH", v); } else { env::remove_var("CUDA_PATH"); }
    }

    // ===== is_torch_available when installed =====

    #[cfg(not(target_os = "windows"))]
    #[test]
    #[serial_test::serial]
    fn test_is_torch_available_true_when_installed() {
        let tmpdir = tempfile::TempDir::new().unwrap();
        std::fs::create_dir_all(tmpdir.path().join("lib")).unwrap();
        std::fs::create_dir_all(tmpdir.path().join("include")).unwrap();
        std::fs::write(tmpdir.path().join("lib").join("libtorch.so"), b"fake").unwrap();

        let old_libtorch = env::var("LIBTORCH").ok();
        env::set_var("LIBTORCH", tmpdir.path());

        assert!(is_torch_available());

        if let Some(v) = old_libtorch { env::set_var("LIBTORCH", v); } else { env::remove_var("LIBTORCH"); }
    }
}

/// Generic TTS Engine Trait - Production-grade modular architecture
/// This allows any TTS implementation to be plugged in
use anyhow::Result;
use async_trait::async_trait;
use serde::{Deserialize, Serialize};
use std::sync::Arc;

use super::audio::AudioData;

/// TTS synthesis parameters
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct SynthesisParams {
    pub speed: f32,
    pub pitch: f32,
    pub voice: Option<String>,
    pub language: Option<String>,
}

impl Default for SynthesisParams {
    fn default() -> Self {
        Self {
            speed: 1.0,
            pitch: 1.0,
            voice: None,
            language: None,
        }
    }
}

/// TTS engine capabilities
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct EngineCapabilities {
    pub name: String,
    pub version: String,
    pub supported_languages: Vec<String>,
    pub supported_voices: Vec<VoiceInfo>,
    pub max_text_length: usize,
    pub sample_rate: u32,
    pub supports_ssml: bool,
    pub supports_streaming: bool,
}

/// Voice information
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct VoiceInfo {
    pub id: String,
    pub name: String,
    pub language: String,
    pub gender: VoiceGender,
    pub quality: VoiceQuality,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub enum VoiceGender {
    Male,
    Female,
    Neutral,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub enum VoiceQuality {
    Standard,
    High,
    Premium,
    Neural,
}

/// Generic TTS Engine trait
#[async_trait]
pub trait TTSEngine: Send + Sync {
    /// Get engine name
    fn name(&self) -> &str;

    /// Get engine capabilities
    fn capabilities(&self) -> &EngineCapabilities;

    /// Synthesize text to speech
    async fn synthesize(&self, text: &str, params: &SynthesisParams) -> Result<AudioData>;

    /// Get available voices
    fn list_voices(&self) -> Vec<VoiceInfo>;

    /// Check if engine is ready
    fn is_ready(&self) -> bool {
        true
    }

    /// Warmup the engine
    async fn warmup(&self) -> Result<()> {
        Ok(())
    }

    /// Validate input text
    fn validate_text(&self, text: &str) -> Result<()> {
        if text.is_empty() {
            anyhow::bail!("Text cannot be empty");
        }

        let max_len = self.capabilities().max_text_length;
        if text.len() > max_len {
            anyhow::bail!("Text too long: {} > {}", text.len(), max_len);
        }

        Ok(())
    }
}

/// TTS Engine factory for creating engines
pub struct TTSEngineFactory;

impl TTSEngineFactory {
    /// Create a production TTS engine by name
    pub fn create(engine_type: &str, config: &serde_json::Value) -> Result<Arc<dyn TTSEngine>> {
        match engine_type {
            // Production engines only
            "kokoro" => Ok(Arc::new(crate::core::kokoro_tts::KokoroEngine::new(config)?)),
            "kokoro-onnx" => Ok(Arc::new(crate::core::kokoro_onnx::KokoroOnnxEngine::new(config)?)),
            "windows-sapi" | "sapi" => {
                #[cfg(target_os = "windows")]
                {
                    Ok(Arc::new(crate::core::windows_sapi_tts::WindowsSAPIEngine::new()?))
                }
                #[cfg(not(target_os = "windows"))]
                {
                    anyhow::bail!("Windows SAPI engine is only available on Windows")
                }
            },
            "piper" => Ok(Arc::new(crate::core::piper_tts::PiperTTSEngine::new(config)?)),
            "vits" => Ok(Arc::new(crate::core::vits_tts::VITSEngine::new(config)?)),
            "styletts2" => Ok(Arc::new(crate::core::styletts2::StyleTTS2Engine::new(config)?)),
            "bark" => Ok(Arc::new(crate::core::bark_tts::BarkEngine::new(config)?)),
            "xtts" => Ok(Arc::new(crate::core::xtts::XTTSEngine::new(config)?)),
            "torch" => Ok(Arc::new(TorchTTSEngine::new(config)?)),
            _ => anyhow::bail!(
                "Unknown engine type: '{}'. Available production engines: kokoro, kokoro-onnx, windows-sapi, piper, vits, styletts2, bark, xtts, torch", 
                engine_type
            ),
        }
    }

    /// List available production engine types
    pub fn available_engines() -> Vec<&'static str> {
        vec!["kokoro", "kokoro-onnx", "windows-sapi", "piper", "vits", "styletts2", "bark", "xtts", "torch"]
    }
}

/// PyTorch-based TTS Engine (placeholder for future ML-based TTS)
pub struct TorchTTSEngine {
    capabilities: EngineCapabilities,
}

impl TorchTTSEngine {
    pub fn new(_config: &serde_json::Value) -> Result<Self> {
        let capabilities = EngineCapabilities {
            name: "PyTorch TTS Engine".to_string(),
            version: "1.0.0".to_string(),
            supported_languages: vec!["en".to_string()],
            supported_voices: vec![],
            max_text_length: 10000,
            sample_rate: 24000,
            supports_ssml: false,
            supports_streaming: false,
        };

        Ok(Self { capabilities })
    }
}

#[async_trait]
impl TTSEngine for TorchTTSEngine {
    fn name(&self) -> &str {
        "torch"
    }

    fn capabilities(&self) -> &EngineCapabilities {
        &self.capabilities
    }

    async fn synthesize(&self, _text: &str, _params: &SynthesisParams) -> Result<AudioData> {
        anyhow::bail!("PyTorch TTS engine requires a trained model. Please configure a model path.")
    }

    fn list_voices(&self) -> Vec<VoiceInfo> {
        vec![]
    }
}

