        let config = GuardConfig {
            max_requests_per_second: 100,
            ..Default::default()
        };
        let guard = SystemGuard::new(config);

        // Set window_start to 2 seconds ago
        {
            let mut ws = guard.request_window_start.write().await;
            *ws = Instant::now() - Duration::from_secs(2);
        }

        // Add 5 requests to the counter manually
        guard.request_count.store(5, Ordering::Relaxed);

        // This call increments count to 6, elapsed >= 1 → fires rate check
        // count 6 <= 100 limit → Ok
        let result = guard.check_request_rate().await;
        assert!(result.is_ok());
