        let key = "client_c";
        // Exhaust the allowance
        for _ in 0..3 {
            let _ = limiter.is_allowed(key);
        }
        // Next request must be rejected
        let result = limiter.is_allowed(key);
        assert!(result.is_err(), "should be Err after limit exceeded");
        let err = result.unwrap_err();
