    #[tokio::test]
    async fn test_register_with_config_json_no_preprocessing() {
        let dir = tempfile::tempdir().unwrap();
        let model_path = dir.path().join("no_pre.onnx");
        std::fs::write(&model_path, b"data").unwrap();

