use std::time::Duration;
use std::future::Future;
use std::pin::Pin;
use tokio::time::sleep;
use rand::Rng;
use tracing::{warn, debug};

#[derive(Debug, Clone)]
pub struct RetryPolicy {
    pub max_retries: usize,
    pub base_delay: Duration,
    pub max_delay: Duration,
    pub multiplier: f64,
    pub jitter: bool,
}

impl Default for RetryPolicy {
    fn default() -> Self {
        Self {
            max_retries: 3,
            base_delay: Duration::from_millis(100),
            max_delay: Duration::from_secs(30),
            multiplier: 2.0,
            jitter: true,
        }
    }
}

impl RetryPolicy {
    pub fn new(max_retries: usize) -> Self {
        Self {
            max_retries,
            ..Default::default()
        }
    }

    pub fn with_delays(
        max_retries: usize,
        base_delay: Duration,
        max_delay: Duration,
    ) -> Self {
        Self {
            max_retries,
            base_delay,
            max_delay,
            ..Default::default()
        }
    }

    /// Execute a function with retry logic
    pub async fn execute<F, Fut, T, E>(&self, mut f: F) -> Result<T, E>
    where
        F: FnMut() -> Fut,
        Fut: Future<Output = Result<T, E>>,
        E: std::fmt::Debug + Clone,
    {
        let mut attempt = 0;
        let mut last_error: Option<E> = None;

        loop {
            match f().await {
                Ok(result) => {
                    if attempt > 0 {
                        debug!(
                            "Operation succeeded after {} retries",
                            attempt
                        );
                    }
                    return Ok(result);
                }
                Err(e) => {
                    attempt += 1;

                    if attempt > self.max_retries {
                        warn!(
                            "Max retries ({}) exceeded. Last error: {:?}",
                            self.max_retries, e
                        );
                        return Err(e);
                    }

                    let delay = self.calculate_delay(attempt);
                    warn!(
                        "Retry attempt {}/{} after {:?}. Error: {:?}",
                        attempt, self.max_retries, delay, e
                    );

                    last_error = Some(e);
                    sleep(delay).await;
                }
            }
        }
    }

    /// Execute with a predicate to determine if error is retryable
    pub async fn execute_if<F, Fut, T, E, P>(&self, mut f: F, is_retryable: P) -> Result<T, E>
    where
        F: FnMut() -> Fut,
        Fut: Future<Output = Result<T, E>>,
        E: std::fmt::Debug + Clone,
        P: Fn(&E) -> bool,
    {
        let mut attempt = 0;

        loop {
            match f().await {
                Ok(result) => {
                    if attempt > 0 {
                        debug!("Operation succeeded after {} retries", attempt);
                    }
                    return Ok(result);
                }
                Err(e) => {
                    if !is_retryable(&e) {
                        debug!("Error is not retryable: {:?}", e);
                        return Err(e);
                    }

                    attempt += 1;

                    if attempt > self.max_retries {
                        warn!(
                            "Max retries ({}) exceeded. Last error: {:?}",
                            self.max_retries, e
                        );
                        return Err(e);
                    }

                    let delay = self.calculate_delay(attempt);
                    warn!(
                        "Retry attempt {}/{} after {:?}. Error: {:?}",
                        attempt, self.max_retries, delay, e
                    );

                    sleep(delay).await;
                }
            }
        }
    }

    fn calculate_delay(&self, attempt: usize) -> Duration {
        let base_ms = self.base_delay.as_millis() as f64;
        let delay_ms = base_ms * self.multiplier.powi(attempt as i32 - 1);
        let capped_ms = delay_ms.min(self.max_delay.as_millis() as f64);

        let final_ms = if self.jitter {
            let mut rng = rand::thread_rng();
            let jitter = rng.gen_range(-0.15..=0.15); // ±15% jitter
            (capped_ms * (1.0 + jitter)).max(0.0)
        } else {
            capped_ms
        };

        Duration::from_millis(final_ms as u64)
    }
}

