        let calls = Arc::new(AtomicUsize::new(0));
        let calls2 = calls.clone();

        // Fail twice (triggers warn! at 84-85 twice), then succeed (triggers
        // debug! at 64-66 because attempt > 0).
        let result = policy
            .execute(|| {
                let c = calls2.clone();
