                    }
                }
            })
            .await;

        assert_eq!(result, Ok(55));
        assert_eq!(calls.load(Ordering::SeqCst), 3);
    }

    /// execute – always fails until max retries exhausted: covers 60 (loop),
    /// 76-77 (warn! "Max retries exceeded"), 84-85 (warn! per retry attempt).
