        // Different keys should have independent limits
        assert!(limiter.try_acquire("key1", 5.0).await);
        assert!(limiter.try_acquire("key2", 5.0).await);

        // Same key should share limit
        assert!(limiter.try_acquire("key1", 5.0).await);
        assert!(!limiter.try_acquire("key1", 1.0).await);
    }

