        // SQL injection
        let sql_input = vec![json!("' OR '1'='1")];
        assert!(validator.validate_inputs(&sql_input).is_err());

        // Command injection
        let cmd_input = vec![json!("$(whoami)")];
        assert!(validator.validate_inputs(&cmd_input).is_err());
