    // ── Line 257: idle index adjustment when a lower-index idle worker is removed ─

    #[tokio::test]
    async fn test_remove_idle_worker_adjusts_indices() {
        // This test exercises line 257: `*val -= 1` adjustment of idle_workers indices
        // when the fallback scan removes a worker at index i while idle_workers still
        // contains a stale entry with value > i.
        //
        // How remove_idle_worker works:
        //   1. pop from idle_workers (fast path) → gets id=X
        //   2. if X is Idle, sets it to Stopping (but doesn't actually remove it from vec!)
        //   3. Fallback scan: iterate from end, find first Idle worker, remove from vec
        //   4. In idle_workers, remove the scanned idx, then adjust all vals > idx by -=1
        //
        // To hit line 257 (the adjustment), we need:
        //   - After step 1 pops something, idle_workers still has entries
        //   - The scan (step 3) removes worker at index i
        //   - idle_workers has a remaining entry j > i → j -= 1
        //
        // Setup:
        //   workers = [0=Idle, 1=Idle, 2=Idle, 3=Processing]  (4 workers, min=1)
        //   idle_workers = [3_stale, 4_stale]  (two stale entries, 3 is now Processing)
        //
        //   Step 1: pop → gets 4_stale. workers.get(4) is None → fast path exits.
        //   Fallback scan (rev): i=3→Processing→skip, i=2→Idle→remove at i=2.
        //   idle_workers = [3_stale]. pos(2) in [3]? No → no removal.
        //   Adjust: 3 > 2 → 3 -= 1 = 2.  ← LINE 257!

        let config = WorkerPoolConfig {
            min_workers: 1,
            max_workers: 10,
            enable_auto_scaling: false,
            ..Default::default()
        };
        let pool = WorkerPool::new(config);
        pool.initialize().await.unwrap(); // 1 worker (id=0)

        // Add workers to get ids 0, 1, 2, 3
        pool.add_worker().await.unwrap(); // id=1
        pool.add_worker().await.unwrap(); // id=2
        pool.add_worker().await.unwrap(); // id=3
        assert_eq!(pool.worker_count().await, 4);

        // Set worker[3] to Processing (so the scan skips it)
        {
            let workers = pool.workers.read().await;
            workers[3].set_state(WorkerState::Processing).await;
        }

        // Manipulate idle_workers: two stale entries (both out-of-range or stale)
        // The first pop will get '4' (out of bounds, so fast path skips it).
        // After the pop, idle_workers still has [3] (stale but valid index for adjustment).
        {
            let mut idle = pool.idle_workers.lock().unwrap();
            idle.clear();
            // Order matters for pop (LIFO): push 3 first, then 4 → pop returns 4 first
            idle.push(3); // stale (worker[3] is Processing)
            idle.push(4); // out-of-bounds
        }

        // workers[0,1,2] are all Idle; workers[3] is Processing
        // idle_workers = [3, 4]
        // Step1: pop → 4. workers.get(4) → None → fast path fails silently.
        // Fallback scan (rev): i=3→Processing→skip, i=2→Idle→remove at i=2.
        // idle_workers = [3]. pos(2) in [3]? No. Adjust: 3>2 → 3-=1=2. LINE 257!

        let result = pool.remove_idle_worker().await;
        assert!(result.is_ok(), "should successfully remove worker at index 2");
        assert_eq!(pool.worker_count().await, 3);

        // The idle_workers entry that was 3 should now be 2 after adjustment
        let idle = pool.idle_workers.lock().unwrap();
        assert!(
            idle.contains(&2),
            "idle index should have been decremented from 3 to 2, got: {:?}", *idle
        );
    }

