    // ── Auto-scaler scale-down path (lines 375-381) ───────────────────────────
    // The auto-scaler captures its own queue_size counter (starts at 0), so
    // scale_down fires when 0 < scale_down_threshold (set to 999) and there
    // are idle workers above min_workers.
    #[tokio::test]
    async fn test_auto_scaler_scale_down_path() {
        let config = WorkerPoolConfig {
            min_workers: 1,
            max_workers: 10,
            scale_up_threshold: 100,      // high so scale-up never fires
            scale_down_threshold: 999,    // always triggers scale-down (queue=0 < 999)
            enable_auto_scaling: true,
            enable_zero_scaling: false,
            health_check_interval_secs: 3600,
            worker_timeout_secs: 300,
        };
        let pool = WorkerPool::new(config);
        pool.initialize().await.unwrap(); // 1 worker
        pool.add_worker().await.unwrap(); // 2
        pool.add_worker().await.unwrap(); // 3 — all idle, above min
        assert_eq!(pool.worker_count().await, 3);

        // Trigger the scaler: scale_down fires, hits lines 376-381
        pool.scale_notify.notify_one();
        tokio::time::sleep(Duration::from_millis(100)).await;

        let _ = pool.worker_count().await;
        pool.shutdown().await;
    }

