        };
        let pool = WorkerPool::new(config);
        pool.initialize().await.unwrap();

        // Set one worker to Processing and record last_active so elapsed >= 0
        {
            let workers = pool.workers.read().await;
            let w = &workers[0];
            w.set_state(WorkerState::Processing).await;
            w.update_last_active().await;
        }

        // Give the health-checker time to iterate (lines 406-407, 410-411, 413-415, 420-421, 425)
        tokio::time::sleep(Duration::from_millis(100)).await;

        pool.shutdown().await;
        tokio::time::sleep(Duration::from_millis(20)).await;
    }

